    public function login()
{
    $user     = trim($this->input->post('user'));
    $password = trim($this->input->post('password'));

    // $user     = trim($this->input->post('user', TRUE));
    // $password = trim($this->input->post('password', TRUE));

    // Validation
    if ($user === '' || $password === '') {
        $this->session->set_flashdata('error_message', '* Invalid username or password.');
        redirect('Menu/main');
        return;
    }

    // Login check
    $dt = $this->Menu_model->user_login_check($user, $password);

    // dd($dt);

    if (empty($dt)) {
        $this->session->set_flashdata('error_message', '* Invalid username or password.');
        redirect('Menu/main');
        return;
    }

    /*
    |--------------------------------------------------------------------------
    | CLEAN SESSION (IMPORTANT FIX)
    |--------------------------------------------------------------------------
    | Store only minimal data to avoid session blob slowdown
    */

    $sessArray = array(
        "id"       => "$dt->id",
        "name"     => "$dt->name",
        "photo"    => "$dt->photo",
        "type_id"  => "$dt->type_id",
        "user_id"  => "$dt->user_id",
    );

    $this->session->set_userdata('user', $sessArray);

    // FORCE session write (prevents lock delays in CI3 database driver)
    session_write_close();

    /*
    |--------------------------------------------------------------------------
    | COOKIES (OPTIMIZED - avoid unnecessary repeated writes)
    |--------------------------------------------------------------------------
    */

    $cookie_time = 60 * 60 * 24 * 30;

    set_cookie([
        'name'     => 'user_id',
        'value'    => $dt->user_id,
        'expire'   => $cookie_time,
        'secure'   => false,
        'httponly' => true
    ]);

    set_cookie([
        'name'     => 'user_name',
        'value'    => $dt->name,
        'expire'   => $cookie_time,
        'secure'   => false,
        'httponly' => true
    ]);

    set_cookie([
        'name'     => 'user_type',
        'value'    => $dt->type_id,
        'expire'   => $cookie_time,
        'secure'   => false,
        'httponly' => true
    ]);

    set_cookie([
        'name'     => 'user_photo',
        'value'    => $dt->photo,
        'expire'   => $cookie_time,
        'secure'   => false,
        'httponly' => true
    ]);

            $cudata = array(
            'user_id'   => $dt->user_id,  
            'log_in'   => 'yes'       
            );
            // Insert into login_session table
            $this->db->insert('login_session', $cudata);

    $this->session->sess_regenerate(TRUE);

    redirect('Menu/Dashboard');
}


