    public function setdateremark(){
        $i = 0;
        date_default_timezone_set("Asia/Calcutta");
        $tdate =  date('Y-m-d');
        $uid = $this->input->post('uid');
        $date = $this->input->post('date');
        $date = strtotime($date);
        $date = date('H:i:s', $date);
        $this->load->model('Menu_model');
        $limit = $this->Menu_model->get_talimit($uid,$tdate);
        foreach($limit as $li){
            $t1 = $aid = $li->time.' ';
            $t2 =  date('H:i:s',strtotime('+10 minutes',strtotime($t1)));
            if($t1<=$date && $t2>=$date){$i++;}
        }
        if($i>0){echo 1;}else{echo 0;}
    }
    public function submittask(){
      
        $this->load->model('Menu_model');
        $this->load->library('session');

        $status=1;$filname="";$tid="";$uid="";$action_id="";$ystatus="";$remark="";$remark_msg="";$noremark="";$purpose="";$nremark_msg="";$rpmmom='null';$mom='null';$flink='null';$flink1='null';$flink2='null';
        $tid = $_POST['tid'];
        $uid = $_POST['uid'];
        $cmpid = $_POST['cmpid'];
        $cstatus = $_POST['ccstatus'];
        $actontaken = $_POST['actontaken'];
        if (isset($_POST['LinkedIn'])) {
        $LinkedIn = $_POST['LinkedIn'];
        }else{
            $LinkedIn = "";
        }
        if(isset($_POST['Facebook'])){
            $Facebook = $_POST['Facebook'];
        }else{$Facebook="";}
        if(isset($_POST['YouTube'])){
            $YouTube = $_POST['YouTube'];
        }else{
            $YouTube = "";
        }
        if(isset($_POST['Instagram'])){
            $Instagram = $_POST['Instagram'];
        }else{$Instagram = "";}
        if(isset($_POST['OtherSocial'])){
            $OtherSocial = $_POST['OtherSocial'];
        }else{$OtherSocial ="";}
        if(isset($_POST['action_id'])){$action_id=$_POST['action_id'];}
        if(isset($_POST['yaction_id'])){$action_id = $_POST['yaction_id'];}
        if(isset($_POST['purpose'])){$purpose = $_POST['purpose'];}
        if(isset($_POST['ystatus'])){$ystatus = $_POST['ystatus'];}
        if(isset($_POST['noremark'])){$noremark = $_POST['noremark'];}
        if(isset($_POST['yremark_msg'])){$yremark = $_POST['yremark_msg'];}
        if(isset($_POST['nremark_msg'])){$nremark = $_POST['nremark_msg'];}
        if(isset($_POST['rpmmom'])){$rpmmom = $_POST['rpmmom'];}
        if(isset($_POST['nadate'])){$nadate = $_POST['nadate'];}else{$nadate='0';}
        // New Log Start
        if(isset($_POST['no_of_school'])){
            $no_of_school = $_POST['no_of_school'];
        }else{
            $no_of_school = "";
        }
        if(isset($_POST['revenue'])){
            $revenue = $_POST['revenue'];
        }else{
            $revenue = "";
        }


        if(isset($_FILES['filname']['name'])){
            $filname = $_FILES['filname']['name'];
            $uploadPath = 'uploads/attachment/';
            $attachment_flink = $this->Menu_model->uploadfile($filname, $uploadPath);
        }else{
            $attachment_flink = 0;
        }

    
  
        
         if($ystatus == 7){
          
            if($no_of_school == ''){
                $this->session->set_flashdata(
                    'error_message',
                    "If you want to update the company status to Closure, please provide the Work Order details, the number of schools, the revenue, and an attachment."
                );
                redirect('Menu/Dashboard');
            }
             
            if($revenue == '' || $revenue == 0){
               
                $this->session->set_flashdata(
                    'error_message',
                    "If you want to update the company status to Closure, please provide the Work Order details, the revenue, and an attachment."
                );
                redirect('Menu/Dashboard');
            } 

            $attachment_flink = $this->Menu_model->uploadWorkOrderfile('filname', 'uploads/pdf/');

            if($attachment_flink == ''){
                $this->session->set_flashdata(
                    'error_message',
                    "If you want to update the company status to Closure, please provide the Work Order details, the attachment."
                );
                redirect('Menu/Dashboard');
            } 
        }


        if(isset($_FILES['filname']['name'])){$filname = $_FILES['filname']['name'];
            $uploadPath = 'uploads/proposal/';
            $this->load->model('Menu_model');
            $flink = $this->Menu_model->uploadfile($filname, $uploadPath);
        }else{$this->load->model('Menu_model');$flink=0;}
        if(isset($_FILES['filname2']['name'])){$filname2 = $_FILES['filname2']['name'];
            $uploadPath = 'uploads/proposal/';
            $this->load->model('Menu_model');
            $flink2 = $this->Menu_model->uploadfile($filname2, $uploadPath);
        }else{$this->load->model('Menu_model');$flink2=0;}
        if(isset($_FILES['filname1']['name'])){$filname1 = $_FILES['filname1']['name'];
            $uploadPath = 'uploads/proposal/';
            $this->load->model('Menu_model');
            $flink1 = $this->Menu_model->uploadfile($filname1, $uploadPath);
        }else{$this->load->model('Menu_model');$flink1=0;}
        if($noremark!=''){$remark=$noremark;}
        if($yremark!=''){$remark=$yremark;}
        if($nremark!=''){$remark=$nremark;}
        if($ystatus!==''){$status=$ystatus;}else{$status=$cstatus;}
        if($purpose==''){$purpose='yes';}
        if($action_id=='7'){
            $partner = $_POST['partner'];
            $noofsc = $_POST['noofsc'];
            $pbudgetme = $_POST['pbudgetme'];
        }else{$partner = "";$noofsc = "";$pbudgetme = "";}
        if($action_id == '1' && $actontaken == 'yes'){
           
            $next_folloup_have_date = $_POST['next_folloup_have_date'];
            $next_folloup_date      = $_POST['next_folloup_date'];
            
            if($next_folloup_have_date !==''){
                if($next_folloup_have_date == 'yes'){
                    if($next_folloup_date !==''){
                        $folloup_data = array(
                            'user_id'                => $uid,
                            'tid'                    => $tid,
                            'next_folloup_have_date' => $next_folloup_have_date,
                            'next_folloup_date'      => $next_folloup_date,
                            'remarks'                => $remark
                        );
                        $this->db->insert('next_folloup_have_date', $folloup_data);
                        $follow_up_insert_id =  $this->db->insert_id();
                        $follow_up_id_data = array(
                            'follow_up_id'  => $follow_up_insert_id
                        );
                        $this->db->where('id', $tid);
                        $this->db->update('tblcallevents', $follow_up_id_data);
                    
                    }else{
                        $this->load->library('session');
                        $this->session->set_flashdata('error_message', '* You have selected Next Follow up have date but you have not selected date. Please select date.');
                        redirect('Menu/Dashboard');
                    }
                }else{
                    $folloup_data = array(
                        'user_id'                => $uid,
                        'tid'                    => $tid,
                        'next_folloup_have_date' => $next_folloup_have_date,
                        'next_folloup_date'      => '',
                        'remarks'                => "$remark"
                    );
                    $this->db->insert('next_folloup_have_date', $folloup_data);
                    $follow_up_insert_id =  $this->db->insert_id();
                    $follow_up_id_data = array(
                        'follow_up_id'  => $follow_up_insert_id
                    );
                    $this->db->where('id', $tid);
                    $this->db->update('tblcallevents', $follow_up_id_data);
                }
            }else{
                $this->load->library('session');
                $this->session->set_flashdata('error_message', '* Please select Next Follow up have date.');
                redirect('Menu/Dashboard');
            }
        }else{
            $follow_up_insert_id = 0;
        }
        
        $id = $this->Menu_model->submit_task($tid,$uid,$cmpid,$actontaken,$action_id,$status,$remark,$rpmmom,$purpose,$flink,$flink1,$flink2,$partner,$noofsc,$pbudgetme,$LinkedIn,$Facebook,$YouTube,$Instagram,$OtherSocial,$nadate,$no_of_school,$revenue,$attachment_flink);
        redirect('Menu/Dashboard');
    }
