    public function startreview(){
        $user           = $this->session->userdata('user');
        $data['user']   = $user;
        $uid            = $user['user_id'];
        $startt         = $_POST['startt'];
        $reviewid       = $_POST['reviewid'];
        $this->load->model('Menu_model');
        $Checkquery         = $this->db->query("SELECT * FROM `allreview` WHERE startt IS NOT NULL and closet IS NULL AND uid='$uid'");
        $CheckqueryData     = $Checkquery->result();
        if(sizeof($CheckqueryData) > 0){
            echo "Allready Start";
        }else{
            $Checkquery         = $this->db->query("SELECT * FROM `allreview` WHERE id = '$reviewid'");
            $CheckqueryData     = $Checkquery->result();
            $reviewPlanDate     = $CheckqueryData[0]->plant;
            $inputDate = $reviewPlanDate;
            $inputDateOnly = date('Y-m-d', strtotime($inputDate));
            $today = date('Y-m-d');
            if ($inputDateOnly <= $today) {
                $startt = date("Y-m-d H:i:s");
                $this->db->where('id', $reviewid);
                $this->db->update('allreview', ['startt' => $startt]);
                // Prepare values for review_session insert
                $psdatetime = date("Y-m-d H:i:s");
                $pstime = date("H:i:s");
                $data = [
                    'user_id'       => $uid,
                    'revew_id'      => $reviewid,
                    'psdatetime'    => $psdatetime,
                    'pstime'        => $pstime,
                    'main_review_on'=> 'ON'
                ];
                // Insert into `review_session`
                $this->db->insert('review_session', $data);
            echo "Start";
            } else {
                echo " * Please check your review date: $inputDate 🗓️. The review cannot start before this date ⏳. It will only begin on $inputDate ✅. ";
            }
        }
    }
