    public  function checkNextPlannerDate($date) {
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $udetail        = $this->Menu_model->get_userbyid($uid);
    $uzone_id       = $udetail[0]->zone_id;
    
    $checkforHoliday    = $this->Menu_model->checkforHolidayByZone($date);
    
    if(sizeof($checkforHoliday) > 0){
        $leave_edate      = $checkforHoliday[0]->leave_edate;
        $leave_zone       = $checkforHoliday[0]->leave_zone;
        if($leave_zone == 'all'){
            $fressPlanningDate  = getNextDate($leave_edate);
            $date               = $fressPlanningDate;
            $checkLeaveForDay   = $this->Menu_model->checkUserLeaveForDay($uid, $date);
            if(sizeof($checkLeaveForDay)  > 0){
                $leave_edate                = $checkLeaveForDay[0]->leave_edate;
                $fressPlanningUDate         = getNextDate($leave_edate);
                $udate                      = $fressPlanningUDate;
                $d1         = new DateTime($date);
                $d2         = new DateTime($udate);
                $bigDate    = ($d1 > $d2) ? $d1->format('Y-m-d') : $d2->format('Y-m-d');
                $date       = $bigDate;
            //     $checkforlHoliday    = $this->Menu_model->checkforHolidayByZone($date);
            //     if(sizeof($checkforlHoliday) > 0){
            //         $leave_edates      = $checkforlHoliday[0]->leave_edate;
            //         $leave_zones       = $checkforlHoliday[0]->leave_zone;
            //         if($leave_zones == 'all'){
            //             $fressPlanningDatel  = getNextDate($leave_edates);
            //             $date               = $fressPlanningDatel;
            //         } if($leave_zones == $uzone_id){
            //             $fressPlanningDatel  = getNextDate($leave_edates);
            //             $date               = $fressPlanningDatel;
                        
            //         }
            //    }
            }
        }else{
            if($leave_zone == $uzone_id){
                $fressPlanningDate  = getNextDate($leave_edate);
                $date               = $fressPlanningDate;
                $checkLeaveForDay   = $this->Menu_model->checkUserLeaveForDay($uid, $date);
                if(sizeof($checkLeaveForDay)  > 0){
                    $leave_edate                = $checkLeaveForDay[0]->leave_edate;
                    $fressPlanningUDate         = getNextDate($leave_edate);
                    $udate                      = $fressPlanningUDate;
                    $d1         = new DateTime($date);
                    $d2         = new DateTime($udate);
                    $bigDate    = ($d1 > $d2) ? $d1->format('Y-m-d') : $d2->format('Y-m-d');
                    $date       = $bigDate;
                }
            }else{
                 $checkLeaveForDay   = $this->Menu_model->checkUserLeaveForDay($uid, $date);
                 if(sizeof($checkLeaveForDay)  > 0){
                    $leave_edate           = $checkLeaveForDay[0]->leave_edate;
                    $fressPlanningUDate    = getNextDate($leave_edate);
                    $udate                 = $fressPlanningUDate;
                    $d1         = new DateTime($date);
                    $d2         = new DateTime($udate);
                    $bigDate    = ($d1 > $d2) ? $d1->format('Y-m-d') : $d2->format('Y-m-d');
                    $date       = $bigDate;
                    
                }
            }
        }
    }else{
        $checkLeaveForDay   = $this->Menu_model->checkUserLeaveForDay($uid, $date);
        if(sizeof($checkLeaveForDay)  > 0){
            $leave_edate                = $checkLeaveForDay[0]->leave_edate;
            $fressPlanningDate          = getNextDate($leave_edate);
            $date                       = $fressPlanningDate;
            $checkforlHoliday    = $this->Menu_model->checkforHolidayByZone($date);
                if(sizeof($checkforlHoliday) > 0){
                    $leave_edates      = $checkforlHoliday[0]->leave_edate;
                    $leave_zones       = $checkforlHoliday[0]->leave_zone;
                    if($leave_zones == 'all'){
                        $fressPlanningDatel  = getNextDate($leave_edates);
                        $date               = $fressPlanningDatel;
                    } if($leave_zones == $uzone_id){
                        $fressPlanningDatel  = getNextDate($leave_edates);
                        $date               = $fressPlanningDatel;
                        
                    }
               }
        }
}
    // Date is a 2nd or 4th Saturday
     if (date('l', strtotime($date)) == 'Saturday') {
        $weekOfMonth = ceil(date('j', strtotime($date)) / 7); // Calculate the week number of the month (1st, 2nd, etc.)
        
        if ($weekOfMonth == 2 || $weekOfMonth == 4) {
            $date = date('Y-m-d', strtotime($date . ' +2 day'));
        }
    }
    // First, check if the given date is a Sunday and adjust to Monday if it is
    if (date('l', strtotime($date)) == 'Sunday') {
        $date = date('Y-m-d', strtotime($date . ' +1 day')); 
    }
    return $date;
}
    public function CheckTodaysPlannerTimeisReadyorNot($uid,$adate){
        
        $this->load->model('Menu_model');
        $this->load->library('session');
    
        if($adate !== date("Y-m-d")){
            $aptime = $this->Menu_model->GetTodaysAutoTaskANDPlanningTime($uid,date("Y-m-d"));
            $aptimecnt = sizeof($aptime);
            if($aptime > 0){
                $start_tttpft = $aptime[0]->start_tttpft;
                $end_tttpft = $aptime[0]->end_tttpft;
                $current_time = date("H:i:s");
                $current_date = date("Y-m-d");
    
                $start_time = new DateTime($start_tttpft);
                $current_time_obj = new DateTime($current_time);
                $interval = $current_time_obj->diff($start_time);
             
                if ($current_time >= $start_tttpft) {
                    // echo "The time has already passed.";
                    $adate2 = $adate;
                    
                    $adate3 = $this->checkNextPlannerDate($adate);
                    if($adate3 !== $adate2){
                        $managecnt = $this->Menu_model->checkforHolidayManageCount($uid,$adate);
                        if($managecnt > 0){
                            redirect("Menu/TaskPlanner2/".$adate3);
                        }else{
                            $managecntf = $this->Menu_model->CheckPlannerManageDate($uid,$adate3);
                            if($managecntf == 0){
                                $this->db->query("INSERT INTO `manage_leave`(`uid`, `planner_date`, `status`) VALUES ('$uid','$adate3','1')");
                            }
                            redirect("Menu/TaskPlanner2/".$adate3); 
                        }
                    }else{
                        $adate = $adate2;
                    }
                } else {
                    $this->session->set_flashdata('error_message_plan',"Time remaining to plan your next day:" . $interval->format('%H hours, %I minutes, and %S seconds'));
                    redirect("Menu/TaskPlanner2/".$current_date); 
                }  
            }
        }
    }
