public  function checkPlannerDate2($date) {
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $udetail        = $this->Menu_model->get_userbyid($uid);
    $uzone_id       = $udetail[0]->zone_id;
    $checkforHoliday    = $this->Menu_model->checkforHolidayByZone($date);
   
    if(sizeof($checkforHoliday) > 0){
        $leave_edate      = $checkforHoliday[0]->leave_edate;
        $leave_zone       = $checkforHoliday[0]->leave_zone;
        if($leave_zone == 'all'){
            $fressPlanningDate  = getNextDate($leave_edate);
            $date               = $fressPlanningDate;
            $checkLeaveForDay   = checkLeaveForDay($uid, $date);
            if(sizeof($checkLeaveForDay)  > 0){
                $leave_edate                = $checkLeaveForDay[0]->leave_edate;
                $fressPlanningDate          = getNextDate($leave_edate);
                $date                       = $fressPlanningDate;
            }
        }else{
            if($leave_zone == $uzone_id){
                $fressPlanningDate          = getNextDate($leave_edate);
                $date                       = $fressPlanningDate;
                
            }
        }
    }else{
        $checkLeaveForDay   = checkLeaveForDay($uid, $date);
        if(sizeof($checkLeaveForDay)  > 0){
            $leave_edate                = $checkLeaveForDay[0]->leave_edate;
            $fressPlanningDate          = getNextDate($leave_edate);
            $date                       = $fressPlanningDate;
        }
}
    // dd($checkLeaveForDay);
    
     if (date('l', strtotime($date)) == 'Saturday') {
        $weekOfMonth = ceil(date('j', strtotime($date)) / 7); // Calculate the week number of the month (1st, 2nd, etc.)
        
        if ($weekOfMonth == 2 || $weekOfMonth == 4) {
            log_message('debug', "Date is a 2nd or 4th Saturday: $date");
            $date = date('Y-m-d', strtotime($date . ' +2 day'));
        }
    }
    // First, check if the given date is a Sunday and adjust to Monday if it is
    if (date('l', strtotime($date)) == 'Sunday') {
        log_message('debug', "Initial date is Sunday, adjusting to Monday: $date");
        $date = date('Y-m-d', strtotime($date . ' +1 day')); // Set to Monday
    }
    echo  $date;
}
