    public function TodaysTaskapprove($id,$type){
        $user = $this->session->userdata('user');
        $data['user'] = $user;
        $uid = $user['user_id'];

        if($type == 'Approve'){

            $status     = "Approved";
            $reamrks    = "Approved By ".$user['name'];
            $apr_time   = date("Y-m-d H:i:s");

            $query      =  $this->db->query("UPDATE `task_plan_for_today` SET `approvel_status`='$status', `action_by`='$uid', `apr_time`='$apr_time',`remarks`='$reamrks' WHERE id = $id");
            
            redirect("Menu/TodaysTaskApprovelRequest");
        }else{
            redirect('Menu/main');
        }
    }
