    public function rpmclose(){
        $this->load->model('Menu_model');
        $this->load->library('session');
        $user = $this->session->userdata('user');
        $data['user'] = $user;
        $uyid =  $user['type_id'];
        $priority="";$closem="";$caddress="";$cpname="";$cpdes="";$cpno="";$cpemail="";
        $uid    = $_POST['uid'];
        $cmid   = $_POST['cmid'];
        $bmcid  = $_POST['bmcid'];
        $bmccid = $_POST['bmccid'];
        $bminid = $_POST['bminid'];
        $bmtid  = $_POST['bmtid'];
        
        if(isset($_POST['priority'])){$priority = $_POST['priority'];}else{$priority = '';}
        $closem = $_POST['closem'];
        $type   = $_POST['type'];
        $caddress = str_replace(["`", "'"], "", $_POST['caddress']);
        $cpname = str_replace(["`", "'"], "", $_POST['cpname']);
        $cpdes  = str_replace(["`", "'"], "", $_POST['cpdes']);
        $cpno   = $_POST['cpno'];
        $cpemail = $_POST['cpemail'];
        $linked_in = $_POST['linked_in'];
        $lat    = $_POST['lat'];
        $lng    = $_POST['lng'];
        $letmeetingsremarks = str_replace(["`", "'"], "", $_POST['letmeetingsremarks']);
        $updateStatus = $_POST['updateCompanyStatus'];
        if(isset($_POST['company_as'])){
            $company_as = $_POST['company_as'];
        }else{
            $company_as = '';
        }
        if(isset($_POST['company_descri'])){
            $company_descri = str_replace(["`", "'"], "", $_POST['company_descri']);
        }else{
            $company_descri = '';
        }
        if(isset($_POST['potentional_client'])){
            $potentional_client = $_POST['potentional_client'];
        }else{
            $potentional_client = '';
        }
          if($type == 'RP' OR $type == 'RPClose' OR $type  == 'Change RP'){
            if(in_array($uyid,[3,13])){
                if($potentional_client == ''){
                 $this->session->set_flashdata('error_message','* Please select the client meetings as potential business clients. All fields are mandatory.');
                 redirect('Menu/Dashboard');
                }
            }
            if($company_as == ''){
                $this->session->set_flashdata('error_message','* Please clarify Company As (About) When you Select RP Meetings.');
                redirect('Menu/Dashboard');
            }
        }
        
    
        $meetingProposalStatus = isset($_POST['meetingProposalStatus']) ? $_POST['meetingProposalStatus'] : '';
       
        $cbmid = $this->Menu_model->close_rpm($uid,$closem,$caddress,$cpname,$cpdes,$cpno,$cpemail,$lat,$lng,$type,$priority,$cmid,$bmcid,$bmccid,$bminid,$bmtid,$letmeetingsremarks,$updateStatus,$company_as,$company_descri,$potentional_client,$meetingProposalStatus,$linked_in);


         if($type == 'RP' OR $type == 'RPClose' OR $type  == 'Change RP'){
            $messaegType = ' ! Please Update Your Lead';
         }else{
            $messaegType = ' By '.$type;
         }

        $this->session->set_flashdata("success_message','Meeting Close SuccessFully $messaegType");
        redirect('Menu/Dashboard');
    }

