        );
    
        $this->db->insert('review_answer', $data);
        $query=$this->db->query("UPDATE main_review SET roster_done='1' WHERE rid ='$roaster_base_review' AND  inid = '$roaster_init_id'");
         // Rostar Review End
         $this->session->set_flashdata('success_message','Roster Review Successfully Submitted !!');
    }
    redirect('Menu/AllReviewPlaing/');
