    public function getcmpbyClusterLocation(){
        $bylocation= $this->input->post('bylocation');
        $uid= $this->input->post('uid');
        $this->load->model('Menu_model');
        $udata = $this->Menu_model->get_userbyid($uid);
        $utype = $udata[0]->type_id;
        if($utype == 3){
           $text = "init_call.mainbd='$uid'";
           $mainuid  = "user_details.user_id = '$uid' AND ";
        }else if($utype == 13){
            $text = "(init_call.mainbd='$uid' OR init_call.clm_id = '$uid')";
            $mainuid  = "user_details.user_id = '$uid' AND ";
        }else if($utype == 4){
            $text = "init_call.apst='$uid'";
            $mainuid  = "";
        }elseif($utype == 19){
            $text = "init_call.ash_nae_co_id = '$uid'";
            $mainuid  = "user_details.user_id = '$uid' AND ";
            $mainuid  = "";
        }elseif($utype == 20){
            $text = "init_call.ash_w_co_id = '$uid'";
            $mainuid  = "";
        }elseif($utype == 21){
            $text = "init_call.ash_s_co_id = '$uid'";
            $mainuid  = "";
        }elseif($utype == 22){
            $text = "init_call.rm_east_co_id = '$uid'";
            $mainuid  = "";
        }elseif($utype == 23){
            $text = "init_call.rm_north_co_id = '$uid'";
            $mainuid  = "";
        }elseif($utype == 24){
            $text = "(init_call.mainbd='$uid' OR init_call.acm_co_id = '$uid')";
            $mainuid  = "user_details.user_id = '$uid' AND ";
            // $text = "init_call.acm_co_id = '$uid'";
            // $mainuid  = "";
        }else{
            $text = "init_call.mainbd='$uid'";
            $mainuid  = "user_id = '$uid' AND ";
        }
        $query2 = $this->db->query("SELECT DISTINCT init_call.id,company_master.compname AS cname, init_call.cluster_id FROM init_call LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id WHERE $text and init_call.cluster_id !=''");
        $data3  = $query2->result();
        
        $clids = '';
        foreach($data3 as $d){
            if($d->cluster_id !=='Select Cluster' || $d->cluster_id > 0){
                $clids .= $d->cluster_id.',';
            }
        }
        $clids = rtrim($clids, ',');
      
        $query3 = $this->db->query("SELECT cluster.*, cluster_mapping.travel_type
        FROM `cluster` 
        LEFT JOIN cluster_mapping on cluster_mapping.cluster_id = cluster.id
        LEFT JOIN user_details on user_details.user_id = cluster_mapping.user_id
        WHERE $mainuid 
        cluster.id in ($clids)");
        $data4  = $query3->result();
        echo '<option value="">Select Cluster Name</option>';
        foreach($data4 as $cmp){
             echo  $data = '<option value='.$cmp->id.'>'.$cmp->clustername.' - ('.$cmp->travel_type.')'.'</option>';
        }
    }
