    //Select user according to role
   public function getRoleUser(){
        $selectedOption = $this->input->post('selectedOption');
        $user           = $this->session->userdata('user');
        $data['user']   = $user;
        $uid            = $user['user_id'];
        if($user['type_id'] == 1){
            $user = $this->db->select('*')->from('user_details')->where(['type_id'=> $selectedOption,'sadmin_id'=>$uid,'status'=>'active'])->get()->result();
        }if($user['type_id'] == 2){
            $user = $this->db->select('*')->from('user_details')->where(['type_id'=> $selectedOption,'admin_id'=>$uid,'status'=>'active'])->get()->result();
        }else if($user['type_id'] == 15){
            $user = $this->db->select('*')->from('user_details')->where(['type_id'=> $selectedOption,'sales_co'=>$uid, 'status'=>'active'])->get()->result();
        }else if($user['type_id'] == 19){
            $user = $this->db->select('*')->from('user_details')->where(['type_id'=> $selectedOption,'ash_nae_co'=>$uid, 'status'=>'active'])->get()->result();
        }else if($user['type_id'] == 4){
            $user = $this->db->select('*')->from('user_details')->where(['type_id'=> $selectedOption,'pst_co'=>$uid, 'status'=>'active'])->get()->result();
        }else if($user['type_id'] == 13){
            $user = $this->db->select('*')->from('user_details')->where(['type_id'=> $selectedOption,'aadmin'=>$uid, 'status'=>'active'])->get()->result();
        }else if($user['type_id'] == 24){
            $user = $this->db->select('*')->from('user_details')->where(['type_id'=> $selectedOption,'acm_co'=>$uid, 'status'=>'active'])->get()->result();
        }else if($user['type_id'] == 24){
            $user = $this->db->select('*')->from('user_details')->where(['type_id'=> $selectedOption,'acm_co'=>$uid, 'status'=>'active'])->get()->result();
        }else if($user['type_id'] == 19){
            $user = $this->db->select('*')->from('user_details')->where(['type_id'=> $selectedOption,'ash_nae_co'=>$uid, 'status'=>'active'])->get()->result();
        }else if($user['type_id'] == 20){
            $user = $this->db->select('*')->from('user_details')->where(['type_id'=> $selectedOption,'ash_w_co'=>$uid, 'status'=>'active'])->get()->result();
        }else if($user['type_id'] == 21){
            $user = $this->db->select('*')->from('user_details')->where(['type_id'=> $selectedOption,'ash_s_co'=>$uid, 'status'=>'active'])->get()->result();
        }else if($user['type_id'] == 22){
            $user = $this->db->select('*')->from('user_details')->where(['type_id'=> $selectedOption,'rm_east_co'=>$uid, 'status'=>'active'])->get()->result();
        }else if($user['type_id'] == 23){
            $user = $this->db->select('*')->from('user_details')->where(['type_id'=> $selectedOption,'rm_north_co'=>$uid, 'status'=>'active'])->get()->result();
        }
        echo  $data = '<option value="">Select User</option>';
        foreach($user as $d){
            echo  $data = '<option value='.$d->user_id.'>'.$d->name.'</option>';
        }
    }
