            $this->load->library('session');
            $this->session->set_flashdata('error_message', ' * Please Add BD Remarks'); 
        }
        if($selcted_bds !=''){
      
                     $clusterCity = implode(",", $clusterCity);
                        $data = array(
                            'clustername'    => $cluster,
