                        foreach($selcted_bd as $bd_uid){
                            $data = array(
                                    'cluster_id' => $insert_id,
                                    'user_id'    => $bd_uid, 
                                    'status'     => 'Active'
                                );
                           $this->db->insert('cluster_mapping', $data);
                        }
                        if($insert_id){
                            $this->load->library('session');
                            $this->session->set_flashdata('success_message', 'Cluster Add successfully');
                        }else{
                            $this->load->library('session');
                            $this->session->set_flashdata('error_message', ' * Cluster Not Added.');    
                        }
        }else{
            $this->load->library('session');
            $this->session->set_flashdata('error_message', ' * User can not be empty. Please Try Again'); 
        }
        // $this->db->query("INSERT INTO `cluster`(`clustername`,`user_id`,`in_state`, `in_district`, `in_city`,`travelType`) VALUES ('$cluster','$selcted_bd','$clusterState','$clusterDistrict','$clusterCity','$typeofTravel','bd_reamrks'=>'$cluster_reamrks')");
     redirect('Menu/CreateTravelCluster');
