public function approveDailyTask(){
    $this->load->model('Menu_model');
    $this->load->library('session');
  
    $user   = $this->session->userdata('user');
    $data['user'] = $user;
    $uid    = $user['user_id'];
    $uyid   =  $user['type_id'];
    $status = $this->input->post('status');
    $tid    = $this->input->post('tid');
    $suser  = $this->input->post('suser');
    $cdate  = date("Y-m-d");
    $taskcount = sizeof($tid);
    $taskaprttime = date("Y-m-d H:i:s");
    if($status){
        if($taskcount > 0){
        foreach($tid as $id){
            $taskData = $this->Menu_model->getTBLTaskByID($id);
            $task_action_id = $taskData[0]->actiontype_id;
            if($status == 'Approve')
            {
                $query =  $this->db->query("UPDATE `tblcallevents` SET `approved_status` = 1, `approved_by`='$uid', `approved_date`='$taskaprttime' WHERE  id = $id");
                if($task_action_id == 3 || $task_action_id == 4 || $task_action_id == 17 || $task_action_id == 22){
                    $query =  $this->db->query("UPDATE `barginmeeting` SET `approved_status` = 1, `approved_by`='$uid' WHERE  tid = $id");
                }
            }
            if($status == 'Reject')
            {
                $query =  $this->db->query("UPDATE `tblcallevents` SET `approved_status` = 0, `approved_by`='$uid',`approved_date`='$taskaprttime', `self_assign`='' WHERE id = $id");
                if($task_action_id == 3 || $task_action_id == 4 || $task_action_id == 17 || $task_action_id == 22){
                    $query =  $this->db->query("UPDATE `barginmeeting` SET `approved_status` = 0, `approved_by`='$uid' WHERE  tid = $id");
                }

                if (in_array($task_action_id, [3, 4])) {

                    if($task_action_id == 3){
                        $ntaction_name = 'Scheduled Meeting';
                    }else if($task_action_id == 4){   
                        $ntaction_name = "Barg in Meeting";
                    }else{
                        $ntaction_name = "";
                    }

                    $currentTaskDetails     =  $this->Menu_model->getTBLTaskBySingleID($id);
                    if(sizeof($currentTaskDetails) > 0){

                        $get_cash_allot     = !empty($currentTaskDetails[0]->cash_allot) ? $currentTaskDetails[0]->cash_allot : 0;
                        $get_task_user_id   = $currentTaskDetails[0]->user_id;
                        $taskUserDetails    = $this->Menu_model->get_userbyid($get_task_user_id);
                        $current_user_cash  = $taskUserDetails[0]->ucash;
                        $updated_cash       = $current_user_cash + $get_cash_allot;

                        $cashData = array(
                            'ucash'  => $updated_cash
                        );
                        $this->db->where('user_id', $get_task_user_id);
                        $this->db->update('user_details', $cashData);

                        $cashlogdata = array(
                            'uid'        => $get_task_user_id,
                            'cash'       => $get_cash_allot,
                            'av_cash'    => $updated_cash,
                            'type'       => "Credit",
                            'remarks'    => "Cash Revert For Rejected $ntaction_name Task ID: $id",
                            'task_id'    => $id
                        );
                        $this->db->insert('cash_log', $cashlogdata);

                    }
                }

                  if($task_action_id == 4 || $task_action_id == 10){
                       $newUnknownLeadsDatas    =  $this->Menu_model->GetUnknownCompanyInformationByTaskID($id);
                       $newUnknownLeadsDatasCNT = sizeof($newUnknownLeadsDatas);
                       if($newUnknownLeadsDatasCNT > 0){
                              $init_call_id     =   $newUnknownLeadsDatas[0]->init_call_id;
                              $company_cid      =   $newUnknownLeadsDatas[0]->cid;
                              $company_name     =   $newUnknownLeadsDatas[0]->compname;
                              $tblcall_taskid   =   $id;
                              $getTaskName      = $this->Menu_model->getTaskAction($task_action_id)[0]->name;
                              $updateData = array(
                                'creator_id'     => 0,
                                'mainbd'         => 0,
                                'insidebd'       => 0,
                                'cstatus'        => 0,
                                'lstatus'        => 0,
                                'bdid'           => 0,
                                'abd'            => 0,
                                'apst'           => 0,
                                'ash_nae_co_id'  => 0,
                                'ash_w_co_id'    => 0,
                                'ash_s_co_id'    => 0,
                                'rm_east_co_id'  => 0,
                                'rm_north_co_id' => 0,
                                'acm_co_id'      => 0,
                                'bpst'           => 0,
                                'cpst'           => 0,
                                'assign_support' => 0
                            );
                            $this->db->where('id', $init_call_id);
                            $this->db->update('init_call', $updateData);

                            // $query =  $this->db->query("UPDATE `tblcallevents` SET `user_id` = 0, `assignedto_id`='0' WHERE  id = $id");

                               $data1 = array(
                                'init_id'           => $init_call_id,
                                'cid'               => $company_cid,
                                'by_task_id'        => $tblcall_taskid,
                                'deleted_by'        => $uid,
                                'deleted_remarks'   => "Company Name: $company_name, and task rejected by $getTaskName.",
                                'update_by'         => $uid
                            );
                        $this->db->insert('company_log', $data1);
                       }
                    }
            }
            $query =  $this->db->query("UPDATE `tblcallevents` SET `approved_date` = '$taskaprttime' WHERE  id = $id");
        }
        $this->session->set_flashdata('success_message','Total '.$taskcount.' Task '.$status.' Successfully');
        redirect('Menu/CheckTaskDetailsByUser/'.$suser.'/'.$cdate);
        }else{
            $this->session->set_flashdata('error_message','* Select At List one Task For '.$status);
            redirect('Menu/CheckTaskDetailsByUser/'.$suser.'/'.$cdate);
        }
    }else{
        $this->session->set_flashdata('error_message','* Please Select Valid Approve / Reject Status');
        redirect('Menu/CheckTaskDetailsByUser/'.$suser.'/'.$cdate);
    }
}
public function selfAssign($tableId, $selfAssign, $taskdate){
        $data = array(
            'self_assign' => $selfAssign,
        );
        $this->db->where('id', $tableId);
        $this->db->update('tblcallevents', $data);
       $query = $this->db->query("SELECT * FROM `tblcallevents` WHERE `id` = $tableId");
       $result = $query->result_array();
        $this->session->set_flashdata('success_message','Request for self assign was sent successfully to the user');
        redirect('Menu/CheckTaskDetailsByUser/'.$result[0]['user_id'].'/'.$taskdate);
    }
