    public function selfTaskAssign(){

    $this->load->model('Menu_model');
    $this->load->library('session');
    $currentUser            = $this->session->userdata('user');
    $current_uid            = $currentUser['user_id'];
    $cudetail               = $this->Menu_model->get_userbyid($current_uid);
    $current_user_name      = $cudetail[0]->name;

    $cuser          = $this->session->userdata('user');
    $taskDetailsJson= $this->input->post('taskDetails');
    $taskDetails    = json_decode($taskDetailsJson, true);
    $eventId        = $taskDetails[0]['id'];
    $filterBy       = "Self Task Assignment";
    $selectby       = "User Assigned Task via Admin Request";
    $task_date      = $this->input->post('date_display');
    
    $time_display   = $this->input->post('time_display');
    $current_status = $this->input->post('current_status');
    $inid           = $this->input->post('company');
    $ntaction       = $this->input->post('task_action');
    $ntppose        = $this->input->post('ntppose');

    $ntdate         = $task_date.' '.$time_display;
    $bdid           = json_decode($taskDetails[0]['user_id'], true);
    $approved_user  = $cuser['user_id'];
    $query          =   $this->db->query("SELECT * FROM init_call where id='$inid'");
    $data           =   $query->result();
    $stid           =   $data[0]->cstatus;
    $cmpid_id       =   $data[0]->cmpid_id;

    $cluster_id     = $data[0]->cluster_id;

    $eventId        = $this->input->post('taskDetails_id');

    if($cluster_id  == '' || $cluster_id == 0){
        $this->session->set_flashdata('error_message',' * Please Assign Cluster to this Company Before Assign Task');
        redirect('Menu/selfTaskAssignPage/'.$eventId);
    }

    $cmpDataq       =  $this->db->query("SELECT * FROM `company_contact_master` WHERE company_id = '$cmpid_id'");
    $cmpData        = $cmpDataq->result();
    $ccid           = $cmpData[0]->id;
    $cmp_data       = $this->Menu_model->get_cmpbyinid($inid);
    $cmp_name       = $cmp_data[0]->compname;

    

    $taskDetailsDatas   = $this->Menu_model->getTBLTaskBySingleID($eventId);
    $bdid               = $taskDetailsDatas[0]->user_id;

    if(sizeof($taskDetailsDatas) > 0){

        if($ntaction == 3 || $ntaction == 4){

        if($ntaction == 3){
            $ntaction_name = 'Scheduled Meeting';
        }else if($ntaction == 4){   
            $ntaction_name = "Barg in Meeting";
        }else{
            $ntaction_name = "";
        }

        $tarUdetail            = $this->Menu_model->get_userbyid($bdid);
        $target_user_cash      = $tarUdetail[0]->ucash;

        if($target_user_cash >= 500){
            $updated_cash = $target_user_cash - 500;

            $cashData = array(
                'ucash'  => $updated_cash
            );
            $this->db->where('user_id', $bdid);
            $this->db->update('user_details', $cashData);

        $tasktdata = array(
            'lastCFID'              => '0',
            'nextCFID'              => '0',
