        );
        
        // Insert data into tblcallevents
        $this->db->insert('tblcallevents',$tasktdata);
        $cntid = $this->db->insert_id();
    
        $meeting_data = array(
            'storedt' => $ntdate,
            'user_id' => $bdid,
            'cid'     => $cmpid_id,
            'ccid'    => $ccid,
            'inid'    => $inid,
            'tid'     => $cntid,
            'company_name' => $cmp_name
        );
        
        $this->db->insert('barginmeeting', $meeting_data);
        $bmid = $this->db->insert_id();

        $cashAllotDatas = array(
            'cash_allot'  => 500
        );
        $this->db->where('id', $cntid);
        $this->db->update('tblcallevents', $cashAllotDatas);

        $cashlogdata = array(
            'uid'        => $bdid,
            'cash'       => 500,
            'av_cash'    => $updated_cash,
            'type'       => "debit",
            'remarks'    => "Cash Deducted for Creating $ntaction_name on $ntdate for Company $cmp_name . Assign Task By $current_user_name",
            'task_id'    => $cntid
        );
        $this->db->insert('cash_log', $cashlogdata);

        $this->session->set_flashdata('success_message','Task Assign SuccessFully!');

        }else{
            $this->session->set_flashdata('error_message','* User Does Not have Sufficient Cash Balance to Assign this Task. Please Contact Admin. ');
            redirect('Menu/selfTaskAssignPage/'.$eventId);
        }

    }else if($ntaction == 22){

        $tasktdata = array(
            'lastCFID'              => '0',
            'nextCFID'              => '0',
            'purpose_achieved'      => 'no',
            'fwd_date'              => $ntdate,
            'actontaken'            => 'no',
            'nextaction'            => 'Will Collect Data by RP Meeting',
