        // Insert data into tblcallevents
        $this->db->insert('tblcallevents',$tasktdata);
        $cntid = $this->db->insert_id();
    
        $meeting_data = array(
            'storedt' => $ntdate,
            'user_id' => $bdid,
            'cid'     => $cmpid_id,
            'ccid'    => $ccid,
            'inid'    => $inid,
            'tid'     => $cntid,
            'company_name' => $cmp_name
        );
        
        $this->db->insert('barginmeeting', $meeting_data);
        $bmid = $this->db->insert_id();

        $this->session->set_flashdata('success_message','Task Assign SuccessFully!');

    }else{

        $createtask_data = array(
            'lastCFID'              => '0',
            'nextCFID'              => '0',
            'remarks'               => '',
            'plan'                  => '1',
            'fwd_date'              => $ntdate,
            'appointmentdatetime'   => $ntdate,
            'actiontype_id'         => $ntaction,
            'purpose_id'            => $ntppose,
            'assignedto_id'         => $bdid,
            'cid_id'                => $inid,
            'status_id'             => $stid,
            'user_id'               => $bdid,
            'date'                  => $ntdate,
            'updateddate'           => $ntdate,
            'selectby'              => $selectby,
            'comments'              => "Assign Task By $current_user_name",
            'comment_by'            => "$current_uid",
            'aftertask'             => "$eventId"
        );
        // Insert data into tblcallevents
        $this->db->insert('tblcallevents', $createtask_data);
        $ntid = $this->db->insert_id();

        $this->session->set_flashdata('success_message','Task Assign SuccessFully!');

    }

        $data = array(
            'self_assign' => 3,
            'nextCFID' => $eventId,
        );
        // Updating the database
        $this->db->where('id', $eventId);
        $this->db->update('tblcallevents', $data);

        $this->session->set_flashdata('success_message','User Assigned Task via Admin Request Successfuly !');
        redirect('Menu/UserTaskViewPage');

    }else{
         $this->session->set_flashdata('error_message','* Request is Invalid.');
        redirect('Menu/selfTaskAssignPage/'.$eventId);
    }

    }



