public function TaskCheck_New($taskid = NULL){
    $user = $this->session->userdata('user');
    $data['user'] = $user;
    $uid = $user['user_id'];
    $uyid =  $user['type_id'];
    $this->load->model('Menu_model');
    $dt=$this->Menu_model->get_utype($uyid);
    ini_set('max_execution_time', 1800); // 300 seconds
    ini_set('memory_limit', '512M');
    $userList = $this->Menu_model->get_userForTask($uid,$uyid);
    $dep_name = $dt[0]->name;
 
    $date = new DateTime();
    $date->modify('-1 day');
    $tdate =  $date->format('Y-m-d');
   
    $taskList   = array();
    $cdate      = date("Y-m-d");
        $yesterday = new DateTime('yesterday');
        // Check if yesterday is Sunday
        if ($yesterday->format('l') === 'Sunday') {
            // Get the day of the month
            $dayOfMonth = $yesterday->format('j');
            
            // Find the week number of the Sunday in the month
            $firstDayOfMonth = (clone $yesterday)->modify('first day of this month');
            $sundaysInMonth = [];
            // Loop through all Sundays in the month
            for ($i = 0; $i < 5; $i++) {
                $sunday = (clone $firstDayOfMonth)->modify("+$i week")->modify('Sunday');
                if ($sunday->format('n') === $yesterday->format('n')) {
                    $sundaysInMonth[] = $sunday->format('j');
                }
            }
            // Check if yesterday is the 2nd or 4th Sunday
            if (in_array($dayOfMonth, [$sundaysInMonth[1], $sundaysInMonth[3]])) {
                
                $date = new DateTime();
                $date->modify('-3 day');
                $tdate =  $date->format('Y-m-d');
            }else{
                $date = new DateTime();
                $date->modify('-2 day');
                $tdate =  $date->format('Y-m-d');
            }
        }else{
            $holy_date          = new DateTime();
            $holy_date->modify('-1 day');
            $holy_tdate         =  $holy_date->format('Y-m-d');
            $checkforHoliday    = checkforHoliday($holy_tdate);
            $checkforHolidaycnt = sizeof($checkforHoliday);
            if($checkforHolidaycnt > 0){
                $holiday_date   = $checkforHoliday[0]->holiday_date;
                $previous_date  = date("Y-m-d", strtotime($holiday_date . " -1 day")); // Subtract 1 day
                $tdate          = $previous_date;
    
                $tcheckforHoliday       = checkforHoliday($previous_date);
                $tcheckforHolidaycnt    = sizeof($tcheckforHoliday);
                if($tcheckforHolidaycnt > 0){
                    $tholiday_date      = $tcheckforHoliday[0]->holiday_date;
                    $tprevious_date     = date("Y-m-d", strtotime($tholiday_date . " -1 day")); // Subtract 1 day
                    $tdate              = $tprevious_date;
                }
            }
$dayName = date('l', strtotime($tdate));
if ($dayName === 'Sunday') {
    // Define yesterday
    $yesterday = new DateTime($tdate);
    $yesterday->modify('-1 day');
    
    // Get the day of the month
    $dayOfMonth = $yesterday->format('j');
    // Find the week number of the Sunday in the month
    $firstDayOfMonth = new DateTime($yesterday->format('Y-m-01'));
    $sundaysInMonth = [];
    // Loop through all Sundays in the month
    for ($i = 0; $i < 5; $i++) {
        $sunday = clone $firstDayOfMonth;
        $sunday->modify("+$i week")->modify('Sunday');
        if ($sunday->format('n') === $yesterday->format('n')) {
            $sundaysInMonth[] = (int) $sunday->format('j');
        }
    }
    // Ensure there are enough Sundays before checking
    if (isset($sundaysInMonth[1]) && isset($sundaysInMonth[3]) && in_array($dayOfMonth, [$sundaysInMonth[1], $sundaysInMonth[3]])) {
        $date = new DateTime($tdate);
        $date->modify('-3 day');
        $tdate = $date->format('Y-m-d');
    } else {
        $date = new DateTime($tdate);
        $date->modify('-1 day');
        $tdate = $date->format('Y-m-d');
    }
}
            
        }
        
        // 2025-03-31
     
        
   
    $RequestApprovals = $this->Menu_model->RequestApprovals($uid);
    $ApprovedRequests = $this->Menu_model->ApprovedRequests($uid);
    if(isset($_POST['userId'])){
        $userId = $_POST['userId'];
        $taskList = $this->Menu_model->getTasks($userId,$tdate);
        $sizeOfTask =sizeof($taskList);
        if(isset($_POST['taskid'])){
            $taskid = $_POST['taskid'];
        }
    }else{
        $userId = '';
        $sizeOfTask = '';
    }
 
    if(!is_null($taskid)){
        $taskData = $this->Menu_model->getTBLSCTaskByID($taskid);
        if (!empty($taskData) && isset($taskData[0]->initiated_datetime)) {
            $taskDatainit = $taskData[0]->initiated_datetime;
            if ($taskDatainit == '0000-00-00 00:00:00' || empty($taskDatainit)) {
                $initiateddttime = date("Y-m-d H:i:s");
                $this->db->set('initiated_datetime', $initiateddttime);
                $this->db->where('id', $taskid);
                $this->db->update('sc_task_events');
                $appointment_datetime = $taskData[0]->appointment_datetime;
                $appointment_datetime = $date = date("Y-m-d", strtotime($appointment_datetime));
            }
        }
    }
    $currentHour = (int) (new DateTime())->format('H:mm');
    if(!empty($user)){
        if($currentHour >= 11 && ($uyid != 2 && $uyid != 15 )) {
            if (sizeof($ApprovedRequests) > 0) {
                $this->load->view($dep_name.'/TaskCheck_New',['uid'=>$uid,'user'=>$user,'userList'=>$userList,'taskList'=>$taskList,'cdate'=>$tdate,'selectedUser'=>$userId,'sizeOfTask'=>$sizeOfTask,'ctaskid'=>$taskid]);
            }else{
                $this->load->view($dep_name.'/RequestForTaskCheckApproval',['uid'=>$uid,'user'=>$user,'cdate'=>$cdate,'RequestApprovals'=>$RequestApprovals,'ctaskid'=>$taskid]);
            }
        }else{
            $this->load->view($dep_name.'/TaskCheck_New',['uid'=>$uid,'user'=>$user,'userList'=>$userList,'taskList'=>$taskList,'cdate'=>$tdate,'selectedUser'=>$userId,'sizeOfTask'=>$sizeOfTask,'ctaskid'=>$taskid]);
        }
    }else{
        redirect('Menu/main');
    }
}
