public function GetFree15MinBlocksForDay($uid,$pdate)
{
    $uid = $this->session->userdata('uid');
    $pdate = $this->input->post('pdate'); // e.g. '2025-07-23'
    $dayStart = '10:00:00';
    $dayEnd = '18:00:00';
    $blockSize = 3; // 3 x 5min = 15min
    // Step 1: Fetch planned tasks for the user
    $query = $this->db->query("
        SELECT 
            CAST(appointmentdatetime AS TIME) AS time_slot,
            COUNT(*) AS task_count
        FROM tblcallevents
        WHERE user_id = ? AND DATE(appointmentdatetime) = ? AND plan = 1
        GROUP BY time_slot
    ", [$uid, $pdate]);
    // Step 2: Build task count array by time
    $booked = [];
    foreach ($query->result() as $row) {
        $booked[$row->time_slot] = $row->task_count;
    }
    // Step 3: Scan day for all 15-minute blocks
    $availableBlocks = [];
    $scanStart = strtotime("$pdate $dayStart");
    $scanEnd = strtotime("$pdate $dayEnd");
    while ($scanStart + ($blockSize * 5 * 60) <= $scanEnd) {
        $slots = [];
        $isAvailable = true;
        $tempStart = $scanStart;
        for ($i = 0; $i < $blockSize; $i++) {
            $slot = date('H:i:s', $tempStart);
            if (!empty($booked[$slot])) {
                $isAvailable = false;
                break;
            }
            $slots[] = $slot;
            $tempStart = strtotime('+5 minutes', $tempStart);
        }
        if ($isAvailable) {
            $availableBlocks[] = $slots;
        }
        $scanStart = strtotime('+5 minutes', $scanStart);
    }
    dd($availableBlocks);
    if (count($availableBlocks) === 0) {
        echo json_encode([
            'status' => 'full',
            'message' => '❌ No free 15-minute block available during the day.',
            'available_blocks' => []
        ]);
    } else {
        echo json_encode([
            'status' => 'ok',
            'message' => '✅ Available blocks fetched successfully.',
            'available_blocks' => $availableBlocks
        ]);
    }
}
