public function session_plan_time_start_taskcheck(){
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           =  $user['type_id'];
    $this->load->model('Menu_model');
    $psdatetime     = date("Y-m-d H:i:s");
    $pstime         = date("H:i:s");
    $savedUserId    = $this->input->post('savedUserId');
    $check_type     = $this->input->post('check_type');
    $check_date     = $this->input->post('check_date');
    $main_review_session = 'START';
    $checkQueryDatas = $this->db->where('user_id', $savedUserId)
        ->where('check_by', $uid)
        ->where('check_date', $check_date) // Assuming column name is actually check_date
        ->where('check_type', $check_type)
        ->where('main_review_on', $main_review_session)
        ->get('task_check_session')
        ->result();
    if (count($checkQueryDatas) == 0) {
        $data = array(
            'user_id'        => $savedUserId,
            'check_date'     => $check_date,
            'psdatetime'     => $psdatetime,
            'pstime'         => $pstime,
            'check_by'       => $uid,
            'check_type'     => $check_type,
            'main_review_on' => $main_review_session
        );
        $this->db->insert('task_check_session', $data);
    }
}
public function session_plan_time_close_task_check(){
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           =  $user['type_id'];
    $this->load->model('Menu_model');
    $pcdatetime     = date("Y-m-d H:i:s");
    $pctime         = date("H:i:s");
    $totaltime      = $_POST['close'];
    $savedUserId    = $this->input->post('savedUserId');
    $check_type     = $this->input->post('check_type');
    $check_date     = $this->input->post('check_date');
    $main_review_session = 'STOP';
    $this->db->where('user_id', $savedUserId);
    $this->db->where('check_by', $uid);
    $this->db->where('check_date', $check_date);
    $this->db->where('check_type', $check_type);
    $this->db->where('main_review_on', 'START');
    $update = $this->db->update('task_check_session', [
        'pctime'        => $pctime,
        'pcdatetime'    => $pcdatetime,
        'totaltime'     => $totaltime,
        'main_review_on'=> $main_review_session
    ]);
    if ($update) {
    // Update successful
    echo "Record updated successfully.";
    } else {
        // Update failed
        echo "Failed to update record.";
    }
    
}
