public function NewBDRequestTask(){
    $user = $this->session->userdata('user');
    $data['user'] = $user;
    $uid = $user['user_id'];
    $uyid =  $user['type_id'];
    $this->load->model('Menu_model');
    $this->load->library('session');
    
    $plandate           = $this->input->post('plandate');
    $bd_client_type     = $this->input->post('bd_client_type');
    $bd_request_rype    = $this->input->post('bd_request_rype');
    $bdreq_plantime     = $this->input->post('bdreq_plantime');
    $request_type_slct  = $this->input->post('request_type_slct');
    $selectrequestcompany  = $this->input->post('selectrequestcompany');
    $selectrequestcompanycnt = sizeof($selectrequestcompany);
    if($selectrequestcompanycnt > 0){
        if($request_type_slct == 'create bd request'){
            if($bd_request_rype == ''){
                $this->session->set_flashdata('error_message',' * Please Select BD Request Type.');
                redirect('Menu/TaskPlanner2/'.$plandate);
            }
            if($bd_client_type == ''){
                $this->session->set_flashdata('error_message',' * Please Select Client Type.');
                redirect('Menu/TaskPlanner2/'.$plandate);
            }
            $k=1;
            $taskAssigntime = $plandate.' '.$bdreq_plantime.':00';
            foreach($selectrequestcompany as $initid){
                    $initidData = $this->Menu_model->get_initbyid($initid);
                    $comp_cstatus = $initidData[0]->cstatus;
                    $comp_lstatus = $initidData[0]->lstatus;
    
                    $taskplanmincount = $taskplanmincount+10;
                    $modifystr = "+$taskplanmincount minutes";
                    if($k==1){$taskplanmincount = 0;}
                    $newdate = new DateTime($taskAssigntime);
                    $modifystr = "+$taskplanmincount minutes";
                    $newdate->modify($modifystr);
                    $new_datetime = $newdate->format('Y-m-d H:i:s');
            
                    $this->Menu_model->CreateBDRequestTask($uid,$new_datetime,$bd_client_type,$bd_request_rype,$initid,$comp_cstatus);
                    $k++;
                }
            $this->session->set_flashdata('success_message',' '.$request_type_slct.' Task Created SuccessFully !!');
            redirect('Menu/TaskPlanner2/'.$plandate);
        }else if($request_type_slct == 'Submit Handover'){
            $k=1;
            $taskAssigntime = $plandate.' '.$bdreq_plantime.':00';
            foreach($selectrequestcompany as $initid){
                
                    $initidData = $this->Menu_model->get_initbyid($initid);
                    $comp_cstatus = $initidData[0]->cstatus;
                    $comp_lstatus = $initidData[0]->lstatus;
    
                    $taskplanmincount = $taskplanmincount+10;
                    $modifystr = "+$taskplanmincount minutes";
                    if($k==1){$taskplanmincount = 0;}
                    $newdate = new DateTime($taskAssigntime);
                    $modifystr = "+$taskplanmincount minutes";
                    $newdate->modify($modifystr);
                    $new_datetime = $newdate->format('Y-m-d H:i:s');
                    $this->Menu_model->CreateSubmitHandoverTask($uid,$new_datetime,$initid,$comp_cstatus);
            }
            $this->session->set_flashdata('success_message',' '.$request_type_slct.' Task Created SuccessFully !!');
            redirect('Menu/TaskPlanner2/'.$plandate);
        }
    }else{
        $this->session->set_flashdata('error_message',' * Please Select minimum 1 comapny for '. $request_type_slct);
        redirect('Menu/TaskPlanner2/'.$plandate);
    }
}
