    $rev_plandate   = $this->input->post('rev_plandate');
    $fdareview_plantimete     = $this->input->post('fdareview_plantimete');
    $rev_startt     = $rev_plandate.' '.$fdareview_plantimete.':00';
    $reviewtype_bdid = $pstid;
    $reviewtype_uid = $bdid;
    // $bdid       = $this->input->post('bdid');
    // $fdate      = $this->input->post('fdate');
    // $pstid      = $this->input->post('pstid');
