            $meetid             = $revData[0]->meetid; 
            $pattern_full       = '/(https?:\/\/[^\s]+)/';
            $modifiedText_full  = preg_replace($pattern_full, '<a href="$1" target="_blank">$1</a>', $meetid);
            $modifiedText_full  = "<strong>Meeting Link : $modifiedText_full</strong>";
            $patternOnlyLink = '/https?:\/\/[^\s]+/';
            if (preg_match($patternOnlyLink, $meetid, $matches)) {
                $firstUrl = $matches[0]; // The first URL is stored in $matches[0]
            } else {
               $firstUrl = '#';
            }
            $revpage = base_url().'Menu/AllReviewPlaing';
        }
         $html .= $slctuser.' <br/><br/>';
         $html .= '<strong>Review Types :</strong> <i>'.$reviewtype.'</i><br/>';
         $html .= ' <strong>Review Start DateTime :</strong> <i>'.$plant.'</i><br/>';
         $html .= '<strong>Review Close DateTime :</strong> <i>'.$review_close_time.'</i><br/><br/>';
         $html .= '<strong>Review Plan Time Remarks :</strong> <i>'.$plan_time_remarks.'</i><br/><br/>';
         $html .= $modifiedText_full.'<br/>';
         $revplanuser = $this->Menu_model->get_userbyid($rev_uid);
         $putype = $revplanuser[0]->type_id;
         $revbyplanuser = $this->Menu_model->get_userbyid($rev_bdid);
         $pbutype = $revbyplanuser[0]->type_id;
         
         $data = [
            'data'=>$html,
            'redirect'=> $firstUrl,
            'revpage'=> $revpage,
            'rev_uid'=> $rev_uid,
            'rev_bdid'=> $rev_bdid,
            'by_type_id'=> $putype,
            'to_type_id'=> $pbutype,
            'cur_type_id'=> $uyid,
         ];
         $datajson = json_encode($data);
        echo $datajson;
    }
}
