            $statusnochangecmp_wdl_nl_cnt = sizeof($statusnochangecmp_wdl_nl);
            if($statusnochangecmp_wdl_nl_cnt > 0){
                foreach($statusnochangecmp_wdl_nl as $logCmp){
                    $logCmp_initid        = $logCmp->inid;
                    $storeLogQuery        = $this->db->query("SELECT * FROM `compulsive_log_test` WHERE `init_id` = '$logCmp_initid' AND DATE(`create_date`) = '$date'"); 
                    $storeLogQueryData    = $storeLogQuery->result();
