public function AddTarget($reviewID = NULL){
    
    $user           =   $this->session->userdata('user');
    $data['user']   =   $user;
    $uid            =   $user['user_id'];
    $uyid           =   $user['type_id'];
    if (empty($user)){redirect('Menu/main');}
    $this->load->model('Menu_model');
    $dt             =   $this->Menu_model->get_utype($uyid);
    $tptime         =   $this->Menu_model->get_tptime($uid);
    $tptime         =   $tptime[0]->tptime;
    $dep_name       =   $dt[0]->name;

    $curFinancialDate       = $this->Menu_model->getFinancialYearRange();
    $sdate                  = $curFinancialDate['start_date'];
    $edate                  = $curFinancialDate['end_date'];
    $max_check_date         = $sdate;


    if(is_null($reviewID) || $reviewID == ''){
        $this->load->library('session');
        $this->session->set_flashdata('error_message', '* Target Setting Only For After Review Complete.');
        redirect('Menu/Dashboard');
    }else{
        $checkReviewExists = $this->Menu_model->getRecordFromAllReviewByID($reviewID);
        if(sizeof($checkReviewExists) == 0){
                $this->load->library('session');
                $this->session->set_flashdata('error_message', '* Review Record Not Matched');
                redirect('Menu/Dashboard');  
        }
    }
    $targetData     =   $this->Menu_model->TargetVSAchievement($uid);
    // $reviewData     =   $this->Menu_model->GetReviewWhichNotSetTargetAchivmentSetting($uid);
    if(!is_null($reviewID)){
        $targetSeetings     = $this->Menu_model->CheckTargetSeetingDoneOrNotByReviewID($reviewID);
        $targetSeetings_cnt = sizeof($targetSeetings);
        if($targetSeetings_cnt == 0){
            $reviewData  = $this->Menu_model->GetCureentReviewDetailsByRID($reviewID);
            $this->load->library('session');
            $this->session->set_flashdata('success_message', '* Good job! You have successfully completed the review. Now you can set the target. Once the target is set, you can close the current review.');
        }else{
            $this->load->library('session');
            $this->session->set_flashdata('success_message', '* Target Setting Allready Done Of This Review.');
            redirect('Menu/Dashboard');
        }  
    }else{
        $reviewData  = '';
    }
    // if($uid == 100059){
    //     $this->load->view('Functions/AddTarget',['uid'=>$uid,'user'=>$user,'targetData'=>$targetData,'reviewData'=>$reviewData,'dep_name'=>$dep_name]);
    // }else{
    //     $this->load->view($dep_name.'/AddTarget',['uid'=>$uid,'user'=>$user,'targetData'=>$targetData,'reviewData'=>$reviewData]);
    // }
    $this->load->view('Functions/AddTarget',[
    'uid'               =>  $uid,
    'user'              =>  $user,
    'targetData'        =>  $targetData,
    'reviewData'        =>  $reviewData,
    'dep_name'          =>  $dep_name,
    'max_check_date'    =>  $max_check_date
    ]);
}
