    $dep_name       =   $dt[0]->name;
    $taskid         = $this->input->post('tid');
    $taskData       =   $this->Menu_model->GetCompanyDetailsByTaskID($taskid);
    $hasPrimary = false;
    foreach ($taskData as $contact) {
        $cid        = $contact->cid;
        $init_cid   = $contact->init_cid;
        $compname   = $contact->compname;
        if ($contact->contact_type === 'primary') {
            $hasPrimary = true;
            break;
        }
    }
        if (!$hasPrimary) {
            $html = "<div class='card' style='margin-bottom: 10px; padding: 10px;' >'Primary Contact' does not exist in this <strong>$compname</strong> . <br>";
            $ccomid = $taskData[0]->cid;
            $html .= "<span style='color: deeppink;'><b>CID : </b>".$ccomid."</span><br>";
            foreach ($taskData as $contact) {
                $cid                = $contact->cid;
                $init_cid           = $contact->init_cid;
                $compname           = $contact->compname;
                $contactperson      = $contact->contactperson;
                $emailid            = $contact->emailid;
                $phoneno            = $contact->phoneno;
                $contact_type       = $contact->contact_type;     
                $html .= "<div class='card' style='margin-bottom: 10px; padding: 10px;background: beige;'>";
                $html .= "<span><b>Contact Person : </b>".$contactperson."</span>";
                $html .= "<span><b>Email ID : </b>".$emailid."</span>";
                $html .= "<span><b>Phone Number : </b>".$phoneno."</span>";
                $html .= "<span><b>Contact Type : </b>".$contact_type."</span>";
                $html .= "</div>";
            }
            $html .="</div>";
            echo $html;
        } 
}
