public function rpminitiate(){
    $uid            = $_POST['uid'];
    $smid           = $_POST['smid'];
    $startm         = $_POST['startm'];
    $company_name   = $_POST['company_name'];
    $cphoto         = $_FILES['cphoto']['name'];
    $uploadPath     = 'uploads/day/';
    $this->load->model('Menu_model');
    $this->load->library('session');
    
       
    $getCurrentMeetingsDatas = $this->Menu_model->CheckVMMeetinfoByid($smid);
        if(sizeof($getCurrentMeetingsDatas) > 0){
            $meeting_link = trim($this->input->post('meeting_link') ?? '');
                if($meeting_link == ''){
                    $this->session->set_flashdata('error_message'," * Please add a virtual meeting link to initiate the meeting.");
                    redirect('Menu/Dashboard');
                }else{
                    $updateMeetData = array(
                        'meeting_link' => $meeting_link
                    );
                    $this->db->where('id', $smid);
                    $this->db->update('barginmeeting', $updateMeetData);
                }
        }
        $cphoto = 'cphoto';
    //   $flink = $this->Menu_model->cphotofile($cphoto, $uploadPath);
       $flink = $this->Menu_model->InitiateMeetingsuploadfile($cphoto, $uploadPath);

    //    $uploadPath1 = 'uploads/meetings/';
    //    $flink1 = $this->Menu_model->uploadfile($cphoto, $uploadPath1);
       
      
       
        $lat = $_POST['lat'];
        $lng = $_POST['lng'];
        $bscid = $_POST['bscid'];
        $cphoto = $flink;
        // var_dump($_POST);die;
        $cbmid = $this->Menu_model->initiate_rpm($uid,$startm,$lat,$lng,$smid,$bscid,$company_name,$cphoto);
        $this->session->set_flashdata('success_message','Meeting Initiated SuccessFully !');
        redirect('Menu/Dashboard');
    }
