public function GetCompanyListIsingWeek(){
    $selectedValue      = $this->input->post('selectedValue');
    $userid             = $this->input->post('userid');
    $week               = $this->input->post('select_week');
    $meetingDone        = $this->input->post('meetingDone');
    $pst_assign         = $this->input->post('pst_assign');
    $cluster_assign     = $this->input->post('cluster_assign');
   
    if($meetingDone == 'yes'){
        $company        =   $this->Menu_model->GetAllCompanyinMeetingsDone($userid,$week);
    }else if($meetingDone == 'no'){
        $company        =   $this->Menu_model->GetAllCompanyinNoMeetingsDone($userid,$week);
    }else if($selectedValue == 'anpnlastweek'){
        $company        =   $this->Menu_model->ManadotoryANPNInWeek($userid,$week);
    }else if($selectedValue == 'will_give_business'){
        $company        =   $this->Menu_model->GetCompListWillGiveBusiness($userid,$week);
    }else if($selectedValue == 'No Status Changes'){
        $company         =   $this->Menu_model->GetCompListNoStatusChanges($userid,$week);
    }else if($selectedValue == 'Review Date with target status achived or not'){
        $company          =   $this->Menu_model->GetCompListReviewTimeTargetNotAchived($userid,$week);
    }else if($meetingDone == '' && $selectedValue == '') {
        if($cluster_assign !== '' && $pst_assign == ''){
            if($cluster_assign == 'yes'){
                $company        =   $this->Menu_model->GetAllCompanyinClusterAssignandNotWork($userid,$week);
            }else{
                $company        =   $this->Menu_model->GetAllCompanyinCLusterNoAssignandNotWork($userid,$week);
            }
        }else if($cluster_assign == '' && $pst_assign !== ''){
            if($pst_assign == 'yes'){
                $company        =   $this->Menu_model->GetAllCompanyinPSTAssignandNotWork($userid,$week);
            }else{
                $company        =   $this->Menu_model->GetAllCompanyinPSTNoAssignandNotWork($userid,$week);
            }
        }else if($cluster_assign !== '' && $pst_assign !== ''){
            if($cluster_assign == 'yes' && $pst_assign == 'yes'){
                $company        =   $this->Menu_model->GetAllCompanyinPSTAndClusterAssignAndNoWork($userid,$week);
            }else if($cluster_assign == 'no' && $pst_assign == 'no'){
                $company        =   $this->Menu_model->GetAllCompanyinPSTCLusterNoAssignandNoWork($userid,$week);
            }else if($cluster_assign == 'yes' && $pst_assign == 'no'){
                $company        =   $this->Menu_model->GetAllCompanyinClusterAssigndANDPSTNoAssignNoWork($userid,$week);
            }else if($cluster_assign == 'no' && $pst_assign == 'yes'){
                $company        =   $this->Menu_model->GetAllCompanyinPSTAssignAndClusterNoAssignNoWork($userid,$week);
            }
        }
    }
    $companyCount           = count($company);
    $data = [
        'company' => $company,
        'companyCount' => $companyCount
    ];
    echo json_encode($data);
}
