        }else if($changedId == 'purpose'){
                
            $company_query = $this->db->query("SELECT init_call.*, init_call.id AS inid, company_master.compname, company_master.id AS cid FROM `init_call` LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN tblcallevents ON tblcallevents.cid_id = init_call.id WHERE init_call.mainbd = $user AND tblcallevents.purpose_achieved = '$purpose'");
        }else if($changedId == 'daysbyplandate'){
            $company_query = $this->db->query("SELECT init_call.*, init_call.id AS inid, company_master.compname, company_master.id AS cid FROM `init_call` LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN tblcallevents ON tblcallevents.cid_id = init_call.id WHERE init_call.mainbd = $user AND tblcallevents.purpose_achieved = $action AND tblcallevents.purpose_achieved = '$purpose' AND tblcallevents.appointmentdatetime >= DATE_SUB(CURDATE(), INTERVAL $daysbyplandate DAY)");
        }else if($changedId == 'action'){
                
            $company_query = $this->db->query("SELECT init_call.*, init_call.id AS inid, company_master.compname, company_master.id AS cid FROM `init_call` LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN tblcallevents ON tblcallevents.cid_id = init_call.id WHERE init_call.mainbd = $user AND tblcallevents.purpose_achieved = $task_action AND tblcallevents.appointmentdatetime >= DATE_SUB(CURDATE(), INTERVAL $daysbyplandatewithtask DAY)");
        }
        $company = $company_query->result();
        // echo $this->db->last_query();
