/* Meeting Report Page Functions 04-12-2024*/
public function meetingReportData($adminid=''){
    //foreach Sales Person
    $getAllBDArray          = $this->Menu_model->getAllBD($adminid);
    $yesterday              = new DateTime('yesterday');
    $user                   = $this->session->userdata('user');
    $data['user']           = $user;
    $data['uid']            = $user['user_id'];
    $data['uyid']           = $user['type_id'];
    if($_POST){
        $sd = $this->input->post('start_date');
        $ed = $this->input->post('end_date');  
    }
   if(!empty($sd) && !empty($ed)){
        $sdate           = $sd; 
        $edate           = $ed;
        $data['sd']      = $sd; 
        $data['ed']      = $ed;
   }
   else{
        if($yesterday->format('l') === 'Sunday'){
            $sdate       = date('Y-m-d', strtotime('-2 day'));
            $edate       = date('Y-m-d', strtotime('-2 day'));
        } else {
            $sdate       = date('Y-m-d', strtotime('-1 day'));
            $edate       = date('Y-m-d', strtotime('-1 day'));
        }
   }
   $totalmeetings =0;$barginmeetings=0;$schedulemeetings=0;$rpmeetings=0;$norpmeetings=0;$onlygotdetail=0;$completed=0;
   $initiated=0;$started=0; 
    foreach($getAllBDArray as $key=>$val){
        $bdid                                                   = $val['user_id'];
        $admin                                                  = $val['admin_id'];
        $meetingSummaryData[$bdid]['TotalMeetingData']          = $this->Menu_model->getMeetingSummaryData($bdid,$sdate,$edate,'0'); //for all type of meetings
        $meetingSummaryData[$bdid]['BarginMeetingData']         = $this->Menu_model->getMeetingSummaryData($bdid,$sdate,$edate,'4');//for barge meeting
        $meetingSummaryData[$bdid]['ScheduleMeetingData']       = $this->Menu_model->getMeetingSummaryData($bdid,$sdate,$edate,'3');//for schedule meeting
        $meetingSummaryData[$bdid]['RPMeetingData']             = $this->Menu_model->getMeetingSummaryData($bdid,$sdate,$edate,'RP'); 
