public function proposalDataReport($adminid = ''){
    $login_id       = $adminid;
    $getAllBDArray  = $this->Menu_model->getAllBD($login_id);
    $yesterday      = new DateTime('yesterday');
    if($_POST){
        $sd = $this->input->post('start_date');
        $ed = $this->input->post('end_date');  
    }
    if(!empty($sd) && !empty($ed)){
            $data['sd'] = $sd; 
            $data['ed'] = $ed;
       }
       else{
          if($yesterday->format('l') === 'Sunday'){
                $sd      = date('Y-m-d', strtotime('-2 day'));
                $ed       = date('Y-m-d', strtotime('-2 day'));
        
            } else {
                $sd       = date('Y-m-d', strtotime('-1 day'));
                $ed       = date('Y-m-d', strtotime('-1 day'));
        
            }
          $data['sd'] = $sd; 
          $data['ed'] = $ed;
       }
//$sd = '2024-12-04'; $ed = '2024-12-05';
    foreach($getAllBDArray as $userId=>$val){
      $proposalData[$val['user_id']] =  $this->Menu_model->getProposalDataReportPerBD($val['user_id'],$sd,$ed);
     //echo $this->db->last_query();exit;
    }
    $meetingcount = array();
    foreach($proposalData as $userkey=>$val){  
        $p =0;$a=0;$p =0;$r=0;
       foreach($val as $k=>$v){
        if($v['apr'] == "2"){
            $r++;
            $meetingcount['rejectedCount'][$userkey] = $r;
         }
         else if($v['apr'] == "1"){
           $a++;
            $meetingcount['approvedCount'][$userkey] = $a;
         }
         else{
          $p++;
            $meetingcount['pendingCount'][$userkey] = $p;
         }
       }  
    }
    $data['meetingcount']         = $meetingcount;
    $data['proposalDataReport']   = $proposalData;
 // dd($data);exit;
    $proposalDataContent = $this->load->view('Admin/proposalDataView',$data,TRUE);
    $this->load->view('Admin/proposalDataView',$data);
return $proposalDataContent;
}
public function handoverDataReport($adminid=''){
    $login_id       = $adminid;
    $getAllBDArray  = $this->Menu_model->getAllBD($login_id);
    if($_POST){
        $sd = $this->input->post('start_date');
        $ed = $this->input->post('end_date');  
    }
   else{
        $yesterday    = new DateTime('yesterday');
        if($yesterday->format('l') === 'Sunday'){
            $sd       = date('Y-m-d', strtotime('-2 day'));
            $ed       = date('Y-m-d', strtotime('-2 day'));
        } else{
            $sd       = date('Y-m-d', strtotime('-1 day'));
            $ed       = date('Y-m-d', strtotime('-1 day'));
        }
        $sdate = $sd;
        $edate = $ed;
   }
    $data['sd'] = $sd; 
    $data['ed'] = $ed;
    $countHandover = 0;
  if(count($getAllBDArray) >0){
    foreach($getAllBDArray as $userId=>$val){
        $handoverDataReport[$val['user_id']] =  $this->Menu_model->gethandoverDataReportPerBD($val['user_id'],$sd,$ed);
        $countHandover = $countHandover + count($handoverDataReport[$val['user_id']]);
      }
      $data['handoverDataReport'] = $handoverDataReport;
  }
  else{
    $data['handoverDataReport'] = array();
  }
  $data['countHandover'] =  $countHandover;
  $handoverhtmlContent    = $this->load->view('Admin/handoverDataView',$data,TRUE);// Render view as string
  $this->load->view('Admin/handoverDataView',$data);
  return $handoverhtmlContent;
}
