public function StoreMandatoryRestriction(){
    $user                   =   $this->session->userdata('user');
    $data['user']           =   $user;
    $uid                    =   $user['user_id'];
    $uyid                   =   $user['type_id'];
    $this->load->model('Menu_model');
    $dt                     =   $this->Menu_model->get_utype($uyid);
    $dep_name               =   $dt[0]->name;
    $user_type              = $this->input->post('user_type');
    $suser_id               = $this->input->post('user_id');
    $an_pn_in_week          = $this->input->post('an_pn_in_week');
    $will_give_business     = $this->input->post('will_give_business');
    $no_status_changes      = $this->input->post('no_status_changes');
    $review_target_achived  = $this->input->post('review_target_achived');
    $categorys              = $this->input->post('categorys');
    $status_id              = $this->input->post('status_id');
    $actions_id             = $this->input->post('actions_id');
    $weeks                  = $this->input->post('weeks');
    $sdate                  = $this->input->post('sdate');
    $edate                  = $this->input->post('edate');
    $meetings_done          = $this->input->post('meetings_done');
    $pst_assign             = $this->input->post('pst_assign');
    $cluster_assign         = $this->input->post('cluster_assign');
    if(!isset($pst_assign)){
        $pst_assign = '';
    }
    if(!isset($cluster_assign)){
        $cluster_assign = '';
    }
    if(!isset($an_pn_in_week)){
        $an_pn_in_week          = 'no';
    }
    if(!isset($will_give_business)){
        $will_give_business     = 'no';
    }
    if(!isset($no_status_changes)){
        $no_status_changes      = 'no';
    }
    if(!isset($review_target_achived)){
        $review_target_achived = 'no';
    }
    if(!isset($status_id)){
        $status_id = '';
    }
    if(!isset($categorys)){
        $categorys = '';
    }
    if(!isset($actions_id)){
        $actions_id = '';
    }
    if(!isset($meetings_done)){
        $meetings_done = '';
    }
    
    foreach($suser_id as $userid){
        $data = array(
            'by_user_id'            => $uid,
            'to_user_id'            => $userid,
            'an_pn_in_week'         => $an_pn_in_week,
            'will_give_business'    => $will_give_business,
            'no_status_changes'     => $no_status_changes,
            'review_target_achived' => $review_target_achived,
            'sdate'                 => $sdate,
            'edate'                 => $edate,
            'week'                  => $weeks,
            'category'              => $categorys,
            'status_id'             => $status_id,
            'actions_id'             => $actions_id,
            'meetings_done'         => $meetings_done,
            'pst_assign'            => $pst_assign,
            'cluster_assign'        => $cluster_assign
        );     
        $this->db->insert('mandatory_restriction', $data);
    }
    $this->load->library('session');
    $this->session->set_flashdata('success_message','Mandatory Restriction for Planner Page SuccessFully Added. ');
    redirect('Menu/MandatoryRestrictionforPlannerPage');
}
