    $uid            =   $user['user_id'];
    $uyid           =   $user['type_id'];
    $this->load->model('Menu_model');
    $roaster_base_rev_id = $this->input->post('roaster_base_rev_id');
    $bdid                = $this->input->post('bdid');
    $slsct_review_id     = $this->input->post('slsct_review_id');
    $slctrevData_base    = $this->Menu_model->getRecordFromAllReviewByID($roaster_base_rev_id);
    $reviewtype_base     = $slctrevData_base[0]->reviewtype;
    $slctrevData         = $this->Menu_model->getRecordFromAllReviewByID($slsct_review_id);
    $reviewtype          = $slctrevData[0]->reviewtype;
    $query =  $this->db->query("UPDATE `allreview` SET `base_review`='$roaster_base_rev_id' WHERE id = $slsct_review_id ");
    $affected_rows = $this->db->affected_rows($query);
    $message = $reviewtype_base.' are set as the base review for the '.$reviewtype;
    echo $message; 
}
public function GetCompanyAfterMeetingDone(){
    $meetingDone   = $this->input->post('meetingDone');
