    $week           = 2;
    if($meetingDone == 'yes'){
        $company        =   $this->Menu_model->GetAllCompanyinMeetingsDone($userid,$week);
    }else{
        $company        =   $this->Menu_model->GetAllCompanyinNoMeetingsDone($userid,$week);
