public function GetAllCompulsiveAndNeedYourAttentionLog(){
    
    $user           =   $this->session->userdata('user');
    $data['user']   =   $user;
    $uid            =   $user['user_id'];
    $uyid           =   $user['type_id'];
     if(empty($user)){redirect('Menu/main');}
    $this->load->model('Menu_model');
    $dt             =   $this->Menu_model->get_utype($uyid);
    $tptime         =   $this->Menu_model->get_tptime($uid);
    $tptime         =   $tptime[0]->tptime;
    $dep_name       =   $dt[0]->name;
    $tdate          = date("Y-m-d");
    if(isset($_POST['bdid'])){
        $tuid           = $_POST['bdid'];
        $alllogData   =   $this->Menu_model->GetAllCompulsiveAndNeedYourAttentionByuid($tuid,$tdate);
    }else{
        $alllogData     =   $this->Menu_model->GetAllCompulsiveAndNeedYourAttention($uid,$tdate);
    }
    $userRemarksCount = [];
    $uniqueUsers = [];
    foreach ($alllogData as $row) {
        $userId     = $row->user_id;
        $userName   = $row->last_task_byuser;
        $remarks    = $row->remarks;
        if (!isset($userRemarksCount[$userId])) {
            $userRemarksCount[$userId] = [];
        }
        if (!isset($userRemarksCount[$userId][$remarks])) {
            $userRemarksCount[$userId][$remarks] = 0;
        }
        $userRemarksCount[$userId][$remarks]++;
        $uniqueUsers[$userId] = $userName;
    }
    
    $this->load->view('Functions/GetAllCompulsiveAndNeedYourAttentionLog',[
    'uid'=>$uid,
    'user'=>$user,
    'alllogData'=>$alllogData,
    'dep_name' =>  $dep_name,
    'userRemarksCount' =>  $userRemarksCount,
    'uniqueUsersLists' =>  $uniqueUsers
]);
  
}
