    $dep_name        = $dt[0]->name;
    $momHtmlContent =  $this->load->view('Admin/momdetailReport',['uid'=>$uid,'user'=>$user,'sdate'=>$sdate, 'edate'=>$edate,'sd'=>$sd,'ed'=>$ed],TRUE);
    $this->load->view('Admin/momdetailReport',['uid'=>$uid,'user'=>$user,'sdate'=>$sdate, 'edate'=>$edate,'sd'=>$sd,'ed'=>$ed]);
    return $momHtmlContent; 
}
