public function AddCashSpentInMeetings(){
    $user                   = $this->session->userdata('user');
    $data['user']           = $user;
    $uid                    = $user['user_id'];
    $meetingids             = $this->input->post('meetingid');
    $expensecash            = $this->input->post('expensecash');
