    $this->load->model('Menu_model');
    $this->load->library('session');

    if (isset($expensecash[0]) && $expensecash[0] < 0) {
        $this->session->set_flashdata('error_message','* Expense amount cannot be negative. Please enter a valid amount.');
        redirect("Menu/UpdateTodaysVisitDetails");
    }

    $meetingidscnt      = sizeof($meetingids);
  
   if (!isset($travel_expense_type) || empty($travel_expense_type)) {
            $this->session->set_flashdata('error_message','* Please select at least one travel expense type.');
            redirect("Menu/UpdateTodaysMeetingsDetails");
    } 
  $expense_string = implode(", ", $travel_expense_type);
    $this->load->library('upload');
    $mergedArray = [];
    foreach ($expensecash as $key => $value) {
        $mergedArray[$value] = $meetingids[$key];
    }
    ksort($mergedArray);

    $i=0; $k=1;

    foreach($meetingids as $meet){

        $expense        = $expensecash[$i];
        $expense_remark = $expense_remarks[$i];
        $images         = $_FILES["images$k"];
        $file_count     = count($images['name']);
        $upload_data    = array();
        $errors         = array();


        $meetingsDatas = $this->Menu_model->getMeetingTaskonTableMId($meet);
        if(sizeof($meetingsDatas) > 0){

            $tbl_taskid    = $meetingsDatas[0]->tid;
            $tblTaskDatas  = $this->Menu_model->getTBLTaskBySingleID($tbl_taskid);

            if(sizeof($tblTaskDatas) > 0){

                $tbl_task_user_id       = $tblTaskDatas[0]->user_id;
                $tbl_cash_allot         = !empty($tblTaskDatas[0]->cash_allot) ? $tblTaskDatas[0]->cash_allot : 0;

                $tuser          = $this->Menu_model->get_userbyid($tbl_task_user_id);
                $ucash          = $tuser[0]->ucash;

                 if($expense > $tbl_cash_allot){
                    $big_ammount = $expense - $tbl_cash_allot;
                    if($ucash < $big_ammount){
                        $this->session->set_flashdata('error_message','* You do not have sufficient cash balance to record this expense. Please check your available cash balance.');
                        redirect("Menu/UpdateTodaysMeetingsDetails");
                    }
                }
            }
        }


        // $tuser          = $this->Menu_model->get_userbyid($uid);
        // $ucash          = $tuser[0]->ucash;
    
        // if($ucash < $expense){
        //     $this->session->set_flashdata('error_message','* You do not have sufficient cash balance to record this expense. Please check your available cash balance.');
        //     redirect("Menu/UpdateTodaysMeetingsDetails");
        // }

        for($l = 0; $l < $file_count; $l++) {

            $_FILES["images$k"]['name']     = $images['name'][$l];
            $_FILES["images$k"]['type']     = $images['type'][$l];
            $_FILES["images$k"]['tmp_name'] = $images['tmp_name'][$l];
            $_FILES["images$k"]['error']    = $images['error'][$l];
            $_FILES["images$k"]['size']     = $images['size'][$l];
            $uploadPath                     = 'uploads/meetings/';

            if (!is_dir($uploadPath)) {
                mkdir($uploadPath, 0777, true);
            }

            $config['upload_path'] = $uploadPath;
            $config['allowed_types'] = '*';
            // $config['max_size'] = 2000;
            $config['encrypt_name'] = TRUE;
            $this->upload->initialize($config);
            if ($this->upload->do_upload("images$k")) {
                $upload_data[] = $this->upload->data();
            } else {
                $errors[] = $this->upload->display_errors();
            }
        }


        if (!empty($upload_data)) {
            $filename = [];
            foreach($upload_data as $data){
                $filename[]= $uploadPath.$data['file_name'];
            }
            $bills = json_encode($filename);
            $this->Menu_model->Addexpensecash($uid,$meet,$expense,$bills,$expense_remark,$expense_string);
            $this->session->set_flashdata('success_message','Meeting Cash Expense added successfully!');
        } else {
            $this->session->set_flashdata('error_message', 'Failed to upload images: ' . implode(', ', $errors));
        }

        $i++;$k++;
    }

    
    redirect("Menu/UpdateTodaysMeetingsDetails");
}







