public function CashExpenseReject(){
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $utype          = $user['type_id'];
    $rejectid       = $this->input->post('reject');
    $rejectreamrk   = $this->input->post('rejectreamrk');
    $verify_date   = Date("Y-m-d H:i:s");
    $this->load->model('Menu_model');
    $this->load->library('session');


    $expenseDatas = $this->Menu_model->GetBDExpenseByEID($rejectid);
    if(sizeof($expenseDatas) > 0){

        $expenseUser            = $expenseDatas[0]->user_id;
        $expenseAmoutnt         = $expenseDatas[0]->expense;
        $expenseUserDetails     = $this->Menu_model->get_userbyid($expenseUser);
        $oldUserCash            = $expenseUserDetails[0]->ucash;
        $newUserCash            = $oldUserCash + $expenseAmoutnt;

            if (in_array($utype, [13, 4, 15, 24,19,20,21,22,23])) {

                $slct_verify        = 'verify';
                $slct_verify_user   = 'verify_by';
                $slct_verify_msg    = 'verify_remarks';
                $slct_verify_date   = 'verify_date';

                $userDatas = array(
                    'ucash'        => $newUserCash
                );

            $this->db->where('user_id', $expenseUser);
            $this->db->update('user_details', $userDatas);

            $cashlogdata = array(
                'uid'        => $expenseUser,
                'cash'       => $expenseAmoutnt,
                'av_cash'    => $newUserCash,
                'type'       => "Credit",
                'remarks'    => "$expenseUser was added back to Meeting Expense because the request was rejected by the Line Manager.",
                'task_id'    => $tid
            );
            $this->db->insert('cash_log', $cashlogdata);

            }else if(in_array($utype,[1,2])){
                $slct_verify        = 'admin_apr';
                $slct_verify_user   = 'admin_by';
                $slct_verify_msg    = 'admin_msg';
                $slct_verify_date   = 'admin_date';

                $userDatas = array(
                    'ucash'        => $newUserCash
                );

                $this->db->where('user_id', $expenseUser);
                $this->db->update('user_details', $userDatas);

                $cashlogdata = array(
                    'uid'        => $expenseUser,
                    'cash'       => $expenseAmoutnt,
                    'av_cash'    => $newUserCash,
                    'type'       => "Credit",
                    'remarks'    => "$expenseUser was added back to Meeting Expense because the request was rejected by the Line Manager.",
                    'task_id'    => $tid
                );
                $this->db->insert('cash_log', $cashlogdata);
            }

            $data = array(
                $slct_verify        => '2',
                $slct_verify_user   => $uid,
                $slct_verify_msg    => $rejectreamrk,
                $slct_verify_date   => $verify_date
            );

            $this->db->where('id', $rejectid);
            $this->db->update('cash_expense', $data);
    }



    $this->session->set_flashdata('error_message','Cash Expense Reject successfully!');
    redirect("Menu/CashExpenseReport");
}
