public function GetScTodaysTask()
{
    $timezone = $this->input->post('timezone');
    $tardate = $this->input->post('tardate');
    $user = $this->session->userdata('user');
    $data['user'] = $user;
    $uid = $user['user_id'];
    $uyid = $user['type_id'];
    $adate = $tardate; // Lowercase 'date' function is standard
    // echo $adate;
    $this->load->model('Menu_model');
    if (strpos($timezone, "Todays Pending") !== false) {
        $timezone = str_replace("Todays Pending ", "", $timezone);
        $adate = date("Y-m-d");
        $usctaskDatas = $this->Menu_model->GetSCTaskDayTypesWithGroupAndDUidDWA_New_Pending($uid, $adate, $timezone);
        $style = 'style="color: #d90d2b;"';
    }else if (strpos($timezone, "Old Pending") !== false) {
        $timezone = str_replace("Old Pending ", "", $timezone);
        $usctaskDatas = $this->Menu_model->GetSCTaskDayTypesWithGroupAndDUidDWA_New_OldPending($uid, $adate, $timezone);
        $style = 'style="color:rgb(255, 8, 45);"';
    } else {
        if ($adate !== date("Y-m-d")) {
            $usctaskDatas = $this->Menu_model->GetSCTaskDayTypesWithGroupAndDUidDWA_NewONEvening($uid, $adate, $timezone);
            $style = 'style="color:rgb(124, 7, 122);"';
        } else {
            $usctaskDatas = $this->Menu_model->GetSCTaskDayTypesWithGroupAndDUidDWA_New($uid, $adate, $timezone);
            $style = 'style="color:rgb(26, 120, 2);"';
        }        
    }
    // Start outputting options
    echo '<option value="">Select Task</option>';
    if (!empty($usctaskDatas)) {
        foreach ($usctaskDatas as $usctaskData) {
            $appointment_datetime = $usctaskData->appointment_datetime;
            if(is_null($appointment_datetime)){
                $appointment_datetime = $usctaskData->type_of_task;
            }else{
                $appointment_datetime = "Planned Time : ".$appointment_datetime;
            }
            echo '<option '.$style.' value="' . htmlspecialchars($usctaskData->id) . '" title="(Type Of Task - ' . htmlspecialchars($usctaskData->type_of_task) . ' - Time Delegated ' . htmlspecialchars($usctaskData->time_delegated) . ')">';
            echo htmlspecialchars($usctaskData->unique_kpa) . ' - (' . htmlspecialchars($appointment_datetime) . ')';
            echo '</option>';
        }
    }
}
public function hurdle_call_checklist($taskid){
    $user            = $this->session->userdata('user');
    $data['user']    = $user;
    $uid             = $user['user_id'];
    $uyid            = $user['type_id'];
    $this->load->library('session');
    $checkhurdledata = $this->db->query("SELECT count(*) as totalrec FROM hurdle_call_data WHERE cast(updated_at as date)=".date('Y-m-d')."");
    $totalresult = $checkhurdledata->row_array();
   if($totalresult['totalrec '] <= 0){
    $data['hurdle_call_data'] = $this->Menu_model->getHurdleCallMOMQuestions();
    $data['uid']      = $uid;
    $data['ctaskid']  = $taskid;
    $data['user']     = $user;
    $data['user']     = $user;
    $dt               = $this->Menu_model->get_utype($uyid);
    $dep_name         = $dt[0]->name;
    $tdate = date("Y-m-d");
    $rquery      =  $this->db->query("SELECT * FROM `sc_task_request` WHERE taskid = '$taskid' AND cast(created_at as Date)= '$tdate'");
    $rqueryData  = $rquery->result();
    $data['rqueryData']     = $rqueryData;
    $taskData = $this->Menu_model->getTBLSCTaskByID($taskid);
    if (!empty($taskData) && isset($taskData[0]->initiated_datetime)) {
        $taskDatainit = $taskData[0]->initiated_datetime;
        if ($taskDatainit == '0000-00-00 00:00:00' || empty($taskDatainit)) {
            $initiateddttime = date("Y-m-d H:i:s");
            $this->db->set('initiated_datetime', $initiateddttime);
            $this->db->where('id', $taskid);
            $this->db->update('sc_task_events');
        }
    }
     if($uyid == '15'){
        $this->load->view($dep_name.'/hurdle_call_checklist_page',$data);
     }
   }
   else{
    $this->session->set_flashdata('warning_message','Hurdle Call Checklist is already submitted for the day');
    redirect('Menu/hurdle_data_report');
   }
   
}
public function insert_hurdleCallData(){
    $data['uid']      = $_SESSION['user']['user_id'];
    $uyid             = $_SESSION['user']['type_id'];
    $dt               = $this->Menu_model->get_utype($uyid);
    $dep_name         = $dt[0]->name;
    $this->load->model('Menu_model');
    $this->load->library('session');
    if($_POST){
        
        $new_checklist                  = $this->input->post('new_checklist');   
        $new_checklist_remark_name      = $this->input->post('new_checklist_remark_name');
        $new_checklist_remark           = $this->input->post('new_checklist_remark');
        if(isset($new_checklist)){
            unset($_POST["new_checklist"], $_POST["new_checklist_remark_name"],$_POST["new_checklist_remark"]);
            $newarraychecklist = [$new_checklist,$new_checklist_remark_name,$new_checklist_remark];
        }
        $newarraychecklistjson = json_encode($newarraychecklist,true);
       
      $data['hurdle_data']    =  $_POST;
     
      $insertId = $this->Menu_model->insertHurdleCallMOMDataPerUser($data);
      if (isset($_FILES['filname']) && !empty($_FILES['filname']['name'])) {
        $filnamecnt =  count($_FILES['filname']);
        $uploadPath = 'uploads/SCDailyActivity/';
        if (!is_dir($uploadPath)) {
            mkdir($uploadPath, 0777, true);
        }
        $filename = $_FILES['filname']['name'];
        if($filnamecnt > 0){
            $flink = $this->Menu_model->MultipleUploadFiles("filname", $uploadPath);
            $flinkjson = json_encode($flink,true);
            $attachment = $flinkjson;
        }else{
            $attachment = 'NULL';
        }
    }else{
        $attachment = 'NULL';
    }
       $updatedatetime = date("Y-m-d H:i:s");
        $data2 = array(
            'complete_datetime' => $updatedatetime,
            'remarks'           => $this->input->post('remarks'),
            'attachment'        =>$attachment,
            'status'            => 1,
            'extra_remarks'     => $newarraychecklistjson
        );
    
        $this->db->where('id',$this->input->post('taskid'));
        $success = $this->db->update('sc_task_events', $data2);
      if ($insertId) {   
        $this->session->set_flashdata('success_message','Hurdle Call Checklist Submitted SuccessFully !');
        redirect('Menu/dashboard');
      }else{
        $this->session->set_flashdata('error_message','Hurdle Call Checklist not Submitted !');
        redirect('Menu/dashboard');
      }
    }
    else{
        redirect('Menu/dashboard');
    }
}
