public function SCTaskPlanner(){
   
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           = $user['type_id'];
    $pdate          = date("Y-m-d");
    $taskid         = $this->input->post('plannercardforsc_select');
    $tasktime       = $this->input->post('sc_plannertime');
    $plannerfilterforsc       = $this->input->post('plannerfilterforsc');
    $plannerfilterforsc_date  = $this->input->post('plannerfilterforsc_date');
    $atasktime      = $plannerfilterforsc_date.' '.$tasktime;
    $this->load->model('Menu_model');
    $this->load->library('session');
 
    if($plannerfilterforsc == "Todays Pending" || $plannerfilterforsc =='Old Pending'){
        $updatedatetime = date("Y-m-d H:i:s");
        $data2 = array(
            'appointment_datetime' => $atasktime
        );
    
        $this->db->where('id',$taskid);
        $success = $this->db->update('sc_task_events', $data2);
        if ($success) {   
            $this->session->set_flashdata('success_message','* Task Updated SuccessFully !');
            redirect('Menu/TaskPlanner2/'.$plannerfilterforsc_date);
          }else{
            $this->session->set_flashdata('error_message','* Task Not Updated.');
            redirect('Menu/TaskPlanner2/'.$plannerfilterforsc_date);
          }
    }else if($plannerfilterforsc =='Todays Task'){
        $data = array(
            'fwd_date'             => $atasktime,
            'sc_task_id'           => $taskid,
            'to_user_id'           => $uid,
            'by_user_id'           => $uid,
            'appointment_datetime' => $atasktime,
            'status'               => 0
        );
        $this->db->insert('sc_task_events', $data);
        if ($this->db->affected_rows() > 0) {
            $this->session->set_flashdata('success_message',' Task Planned Successfully !!');
            redirect('Menu/TaskPlanner2/'.$plannerfilterforsc_date);
        } else {
            $this->session->set_flashdata('success_message',' Failed to Task Planned.');
            redirect('Menu/TaskPlanner2/'.$plannerfilterforsc_date);
        }
    }
}
