    $queryDataResult    =  $queryData->result();
   dd($queryDataResult);
    foreach($queryDataResult as $result){
         $username   = $result->name;
         $usimg      = $result->usimg;
         $ucimg      = $result->ucimg;
        if($usimg !== 'uploads/day/')
            echo "<br/>=================== $username =================<br/><br/>".' Start Image = '.$usimg."<br/>";
            $file_path = $usimg;
            $upload_path = 'uploads/day/';
            $compress = $this->Menu_model->CompressAndReUploadImageWhenIsExists($file_path, $upload_path);
            echo $compress."<br/><br/>";
        }
        
        if(!is_null($ucimg)){
            if($ucimg !== 'uploads/day/'){
                echo ' Close Image = '.$ucimg."<br/>";
                $file_path = $ucimg;
                $upload_path = 'uploads/day/';
                $compress = $this->Menu_model->CompressAndReUploadImageWhenIsExists($file_path, $upload_path);
                echo $compress."<br/><br/>";
            }
        }
        echo "<br/>";
    }
   
  
