public function SelfANDTeamDAR($taskid){
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           = $user['type_id'];
    $pdate          = date("Y-m-d");
    $this->load->model('Menu_model');
    $this->load->library('session');
    $dt             = $this->Menu_model->get_utype($uyid);
    $dep_name       = $dt[0]->name;
    
    $taskData = $this->Menu_model->getTBLSCTaskByID($taskid);
    $appointment_datetime = $taskData[0]->appointment_datetime;
    if (!empty($taskData) && isset($taskData[0]->initiated_datetime)) {
        $taskDatainit = $taskData[0]->initiated_datetime;
        if ($taskDatainit == '0000-00-00 00:00:00' || empty($taskDatainit)) {
            $initiateddttime = date("Y-m-d H:i:s");
            $this->db->set('initiated_datetime', $initiateddttime);
            $this->db->where('id', $taskid);
            $this->db->update('sc_task_events');
        }
    }
    $query= $this->db->query("SELECT * FROM user_details where sales_co='$uid' and status='active' and (type_id=3 or type_id=4 || type_id=13) || user_id = $uid");
    $usersData = $query->result();
    $this->load->view($dep_name.'/SelfANDTeamDAR',['uid'=>$uid,'user'=>$user,'usersData'=>$usersData,'appointment_datetime'=>$appointment_datetime,'ctaskid'=>$taskid]);
}
