public function GetUserMappingFiled(){
    $zoneid         = $this->input->post('zoneid');
    $slsct_usertype = $this->input->post('slsct_usertype');
    $useradmin      = $this->input->post('useradmin');
    $this->load->model('Menu_model');
    // zone_id = '$zoneid'
    $mainsql = "SELECT user_details.*,user_zone.name as user_zone_name FROM `user_details` 
LEFT JOIN user_zone on user_zone.id = user_details.zone_id";
    $userstatus = 'AND status = "active"';
    if($slsct_usertype == 3){
        $bdquery            =   $this->db->query("$mainsql WHERE user_details.admin_id = '$useradmin' $userstatus");
    }else if($slsct_usertype == 13){
        $bdquery            =   $this->db->query("$mainsql WHERE user_details.admin_id = '$useradmin' $userstatus");
    }else if($slsct_usertype == 4){
        $bdquery            =   $this->db->query("$mainsql WHERE user_details.admin_id = '$useradmin' $userstatus");
    }else if($slsct_usertype == 15){
        $bdquery            =   $this->db->query("$mainsql WHERE user_details.admin_id = '$useradmin' $userstatus");
    }else if($slsct_usertype  == 18 || $slsct_usertype  == 19 || $slsct_usertype  == 20 || $slsct_usertype  == 21 || $slsct_usertype  == 22 || $slsct_usertype  == 23 || $slsct_usertype  == 24){
        $bdquery            =   $this->db->query("$mainsql where user_details.admin_id = '$useradmin' AND user_details.status = 'active'");
    }else{
        $bdquery            =   $this->db->query("$mainsql where user_details.status = 'active'");
    }
    $allteam            =   $bdquery->result();
    $allteamjson = json_encode($allteam,true);
    echo $allteamjson;
}
