public function StoreUserOnDatabase(){
    
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           = $user['type_id'];
    $pdate          = date("Y-m-d");
    $this->load->model('Menu_model');
    $this->load->library('session');
    $dt             = $this->Menu_model->get_utype($uyid);
    $dep_name       = $dt[0]->name;
    $date = date("Y-m-d");
    $firstname       = $this->input->post('firstname');
    $lastname        = $this->input->post('lastname');
    $username        = $this->input->post('usernametype');
   
    $email           = $this->input->post('email');
    $phone           = $this->input->post('phone');
    $dob             = $this->input->post('dob');
    $country         = $this->input->post('country');
    $state           = $this->input->post('state');
    $district        = $this->input->post('district');
    $city            = $this->input->post('city');
    $address         = $this->input->post('address');
    $password        = $this->input->post('password');
    $confirmPassword = $this->input->post('confirmPassword');
    $zone_id         = $this->input->post('zone');
    $type_id         = $this->input->post('type_id');
    $admin_id        = $this->input->post('admin_id');
    $selectbd        = $this->input->post('selectbd'); // This will fetch the entire array
    $clustermanager  = $this->input->post('clustermanager'); // This will fetch the entire array
    $userpst         = $this->input->post('userpst');        // This will fetch the entire array
    $sales_coordinator  = $this->input->post('sales_coordinator'); // This will fetch the entire array
    $inside_sales       = $this->input->post('inside_sales'); // This will fetch the entire array

