         $query =  $this->db->query("UPDATE `user_details` SET `rm_east_co`='$authUserId' WHERE user_id IN ($assistant_cluster_manager_user_ids)");
        // Closed To ACM
    }
    else if($type_id == 23){
       
        $selectbds          = !empty($selectbd) ? implode(',', $selectbd) : '';
        $clustermanagers    = !empty($clustermanager) ? implode(',', $clustermanager) : '';
        $userpsts           = !empty($userpst) ? implode(',', $userpst) : '';
        $sales_coordinators = !empty($sales_coordinator) ? implode(',', $sales_coordinator) : '';
        // Combine the non-empty values
        $updates_user_id = trim($selectbds . ',' . $clustermanagers,',');
        // If $updates_user_id is empty, set it to null or an empty value
        if (empty($updates_user_id)) {
            $updates_user_id = ''; // Or null, depending on your requirement
        }
        $query =  $this->db->query("UPDATE `user_details` SET `rm_north_co`='$authUserId' WHERE user_id IN ($updates_user_id)");
