        }else if($ashDatas_type_id == 20){ // 20 - Assistant Sales Head (W)
            $query =  $this->db->query("UPDATE `user_details` SET `ash_w_co`='$assistant_sales_head_user_id' WHERE user_id = '$authUserId'");
        }else if($ashDatas_type_id == 21){ // 21 - Assistant Sales Head (S)
            $query =  $this->db->query("UPDATE `user_details` SET `ash_s_co`='$assistant_sales_head_user_id' WHERE user_id = '$authUserId'");
        }
        // Closed To Map Assistant Sales Head
        // Start To ACM
         $query =  $this->db->query("UPDATE `user_details` SET `rm_north_co`='$authUserId' WHERE user_id IN ($assistant_cluster_manager_user_ids)");
        // Closed To ACM
    }
    
    else if($type_id == 24){
       
        $selectbds          = !empty($selectbd) ? implode(',', $selectbd) : '';
        $clustermanagers    = !empty($clustermanager) ? implode(',', $clustermanager) : '';
        $userpsts           = !empty($userpst) ? implode(',', $userpst) : '';
        $sales_coordinators = !empty($sales_coordinator) ? implode(',', $sales_coordinator) : '';
        // Combine the non-empty values
        $updates_user_id = trim($selectbds . ',' . $clustermanagers,',');
        // If $updates_user_id is empty, set it to null or an empty value
        if (empty($updates_user_id)) {
            $updates_user_id = ''; // Or null, depending on your requirement
        }
        $query =  $this->db->query("UPDATE `user_details` SET `acm_co`='$authUserId' WHERE user_id IN ($updates_user_id)");
        $assistant_sales_head_user_id           = $assistant_sales_head[0];
        $regional_manager_user_id               = $regional_manager[0];
        $sales_coordinator_user_id              = $sales_coordinator[0];
              // Start To Map Assistant Sales Head
        $ashDatas           = $this->Menu_model->get_userbyid($assistant_sales_head_user_id);
        $ashDatas_type_id   = $ashDatas[0]->type_id;
        if($ashDatas_type_id == 19){ // 19- Assistant Sales Head (NAE)
            $query =  $this->db->query("UPDATE `user_details` SET `ash_nae_co`='$assistant_sales_head_user_id' WHERE user_id = '$authUserId'");
        }else if($ashDatas_type_id == 20){ // 20 - Assistant Sales Head (W)
            $query =  $this->db->query("UPDATE `user_details` SET `ash_w_co`='$assistant_sales_head_user_id' WHERE user_id = '$authUserId'");
        }else if($ashDatas_type_id == 21){ // 21 - Assistant Sales Head (S)
            $query =  $this->db->query("UPDATE `user_details` SET `ash_s_co`='$assistant_sales_head_user_id' WHERE user_id = '$authUserId'");
        }
        // Closed To Map Assistant Sales Head
        // Start To Map Regional Manager
        $rmDatas           = $this->Menu_model->get_userbyid($regional_manager_user_id);
        $rmDatas_type_id   = $rmDatas[0]->type_id;
        if($rmDatas_type_id == 22){ // 22 - RM East
             $query =  $this->db->query("UPDATE `user_details` SET `rm_east_co`='$regional_manager_user_id' WHERE user_id = '$authUserId'");
        }else if($rmDatas_type_id == 23){ // 23 - RM North
             $query =  $this->db->query("UPDATE `user_details` SET `rm_north_co`='$regional_manager_user_id' WHERE user_id = '$authUserId'");
        }
        // Closed To Map Regional Manager
        $query =  $this->db->query("UPDATE `user_details` SET `sales_co`='$sales_coordinator_user_id' WHERE user_id = '$authUserId'");
    }
    
    else{
        $this->session->set_flashdata('error_message',"Department is InActive");
        redirect('Menu/UserRegistrationNew/');
    }
    // Close To Create New User On Organations
    $this->session->set_flashdata('success_message',"User successfully created in the department of <strong>$type_status_name</strong>. The name is '$fullname', and the username is the '$username' with the password '$password'.");
    redirect('Menu/UserRegistrationNew/');
}else{
    $type_statusquery       =   $this->db->query("SELECT * FROM `user_type` WHERE id = '$type_id'");
