public function EditUserInformationsAndMapping($targetuid){
    $user = $this->session->userdata('user');
    $data['user'] = $user;
    $uid = $user['user_id'];
    $uyid =  $user['type_id'];
    $this->load->model('Menu_model');
        if ($uyid != 1 && $uyid != 2) {
            redirect('Menu/main');
        }
    $dt=$this->Menu_model->get_utype($uyid);
    $dep_name = $dt[0]->name;
    $userDetailsq       =   $this->db->query("SELECT * FROM `user_details` WHERE user_id = '$targetuid'");
    $userDetails        =   $userDetailsq->result();
    $zone           =   $this->Menu_model->getZone();
    $allusertypes   =   $this->Menu_model->get_user_type();
    $adminquery     =   $this->db->query("Select * from user_details where type_id IN (2) and status = 'active'");
    $usersadmin     =   $adminquery->result();
    $countryquery   =   $this->db->query("SELECT * FROM `country_db`");
    $userscountrys  =   $countryquery->result();
    $statequery     =   $this->db->query("SELECT * FROM `in_state`");
    $usersstates    =   $statequery->result();
    if(!empty($user)){
        $this->load->view($dep_name.'/EditUserInformationsAndMapping',['user'=>$user,'uid'=>$uid, 'userDetails'=>$userDetails,'targetuid'=>$targetuid,'zone'=>$zone,'allusertypes'=>$allusertypes,'usersadmins'=>$usersadmin,'userscountrys'=>$userscountrys,'usersstates'=>$usersstates]);
    }else{
        redirect('Menu/main');
    }
}
