    $rm_north_co_user_id    = $usersData[0]->rm_north_co;
    $acm_co_user_id         = $usersData[0]->acm_co;
    $slctuser_id            = '';
    if((!empty($aadmin_user_id) || !is_null($aadmin_user_id)) && ($aadmin_user_id !== 0)){
        $slctuser_id        .= $aadmin_user_id;
    }
    if((!empty($pst_co_user_id) || !is_null($pst_co_user_id)) && $pst_co_user_id !== 0){
        if($slctuser_id !==''){
            $slctuser_id        .= ','. $pst_co_user_id;
        }else{
            $slctuser_id        .= $pst_co_user_id;
        }
    }
    if((!empty($sales_co_user_id) || !is_null($sales_co_user_id)) && $sales_co_user_id !== 0){
