            $slctuser_id        .= ','. $ash_s_co_user_id;
        }else{
            $slctuser_id        .= $ash_s_co_user_id;
        }
    }
    if((!empty($rm_east_co_user_id) || !is_null($rm_east_co_user_id)) && $rm_east_co_user_id !== 0){
