            $slctuser_id        .= ','. $rm_east_co_user_id;
        }else{
            $slctuser_id        .= $rm_east_co_user_id;
        }
    }
    if((!empty($rm_north_co_user_id) || !is_null($rm_north_co_user_id)) && $rm_north_co_user_id !== 0){
        if($slctuser_id !==''){
            $slctuser_id        .= ','. $rm_north_co_user_id;
        }else{
            $slctuser_id        .= $rm_north_co_user_id;
        }
