    if((!empty($acm_co_user_id) || !is_null($acm_co_user_id)) && $acm_co_user_id !== 0){
        if($slctuser_id !==''){
            $slctuser_id        .= ','. $acm_co_user_id;
        }else{
            $slctuser_id        .= $acm_co_user_id;
        }
    }
    if($slsct_type_id  == 2){
        $allTeamsInfo     =   $this->db->query("Select * from user_details where admin_id = '$targetuid'")->result();
    }else if($slsct_type_id  == 15){
        $allTeamsInfo     =   $this->db->query("Select * from user_details where sales_co = '$targetuid' OR user_id IN ($slctuser_id)")->result();
    }else if($slsct_type_id  == 4){
        $allTeamsInfo     =   $this->db->query("Select * from user_details where pst_co = '$targetuid' OR user_id IN ($slctuser_id)")->result();
