// Start To Find Company BY - Created or update date
public function FindCompanyBy(){
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           =  $user['type_id'];
    $this->load->model('Menu_model');
    $cuser_id               = $this->input->post('user_id');
    $adate                  = $this->input->post('adate');
    $findCompanyBySelect    = $this->input->post('findCompanyBySelect');
    $findCompanyByDate      = $this->input->post('findCompanyByDate');
    $bytask                 = $this->input->post('findCompanyByTaskSelect');
    $bystatus               = $this->input->post('findCompanyByStatusSelect');
    
    if($findCompanyBySelect !== ''){
        if(!isset($bytask)){
            $bytask = 0;
        }
        if(!isset($bystatus)){
            $bystatus = 0;
        }
        $getcmpData  =  $this->Menu_model->FidCompanyAfterDateBy($cuser_id,$findCompanyByDate,$findCompanyBySelect,$bytask,$bystatus);
        echo '<option value="">Select Company</option>';
        foreach($getcmpData as $cmp){
            $cstatus = $cmp->cstatus;
            $datapoint = [
                'current_status' => $cmp->cstatus_name,
                'mainbd_name' => $cmp->mainbd_name,
                'cluster_manager_name' => $cmp->clm_name,
                'pst_name' => $cmp->pst_name,
                'approved_by_name' => $cmp->apr_by_name,
                'created_datet' => $cmp->created_at,
                'approved_date' => $cmp->apr_date,
                'task_name' => $cmp->action_name
            ];
            $readableKey = '';
            foreach($datapoint as $kindex => $kvalue){
                $readableKeys = ucwords(str_replace('_', ' ', $kindex));
                $readableKey  .= $readableKeys.' : '.$kvalue.' ';
            }
            if($cmp->compname == 'Unknown'){continue;}
            $cid = $cmp->cid;
            ?>
            <option style="color:rgb(229, 1, 111);" title="<?=$readableKey?>" value="<?=$cmp->init_id?>">
            <?=$cid?> -  <?=$cmp->compname?>
                (<?=$cmp->cstatus_name?>)
            </option>
                <?php
                }
    }
}
