public function AddOrUpdateCompanyContactDtails(){
    $user           =   $this->session->userdata('user');
    $data['user']   =   $user;
    $uid            =   $user['user_id'];
    $uyid           =   $user['type_id'];
    $this->load->model('Menu_model');
    $this->load->library('session');
    $dt             =   $this->Menu_model->get_utype($uyid);
    $dep_name       = $dt[0]->name;
    $outputArray = [];
    $inputArray = $this->input->post();
    foreach ($inputArray['contactperson'] as $index => $contactPerson) {
        $outputArray[] = [
            "company_id"    => isset($inputArray['company_id']) ? $inputArray['company_id'] : null,
            "ccid"          => isset($inputArray['ccid'][$index]) ? $inputArray['ccid'][$index] : null,
            "contactperson" => isset($inputArray['contactperson'][$index]) ? $inputArray['contactperson'][$index] : null,
            "emailid"       => isset($inputArray['emailid'][$index]) ? $inputArray['emailid'][$index] : null,
            "phoneno"       => isset($inputArray['phoneno'][$index]) ? $inputArray['phoneno'][$index] : null,
            "designation"   => isset($inputArray['designation'][$index]) ? $inputArray['designation'][$index] : null,
            "type"          => isset($inputArray['type'][$index]) ? $inputArray['type'][$index] : null
        ];
    }
    if (!empty($outputArray)) {
        foreach ($outputArray as $array) {
            if (empty($array['ccid'])) {
                unset($array['ccid']);
                $array['createddate']   = date('Y-m-d');
                $array['add_by']        = $uid;
                $this->db->insert('company_contact_master', $array);
            }else{
                $company_id         = $array['company_id'];
                $contactperson      = $array['contactperson'];
                $emailid            = $array['emailid'];
                $phoneno            = $array['phoneno'];
                $designation        = $array['designation'];
                $type               = $array['type'];
                $ccFindQuery        = $this->db->query("SELECT * FROM company_contact_master WHERE `company_id` = '$company_id' AND `contactperson` = '$contactperson' AND `emailid` = '$emailid' AND `phoneno` = '$phoneno' AND `designation` = '$designation' AND `type` = '$type'");
                $ccFindQueryData    = $ccFindQuery->result();
                if(sizeof($ccFindQueryData) == 0){
                    unset($array['ccid']);
                    $array['createddate']   = date('Y-m-d');
                    $array['add_by']        = $uid;
                    $this->db->insert('company_contact_master', $array);
                }else{
                    $ccids = $array['ccid'];
                    unset($array['ccid']);
                    unset($array['company_id']);
                    $this->db->where('id',$ccids);
                    $success = $this->db->update('company_contact_master', $array);
                }
            }
        }
    }
    $this->session->set_flashdata('success_message',"* Company Contact Updated Successfully.");
    redirect('Menu/GetAllCompaniesThatDoNotHavePrimaryContactDetailsData/');
}
