public function TeamDayBeforeTaskReviewCheckingInCRMApp($taskid){
   
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           = $user['type_id'];
    $pdate          = date("Y-m-d");
    $this->load->model('Menu_model');
    $this->load->library('session');
    $dt             = $this->Menu_model->get_utype($uyid);
    $dep_name       = $dt[0]->name;
    $tdate = date("Y-m-d");
    $getAllUserData    = $this->Menu_model->GetDailyTeamPlannerSummaryWwithLocationShareNew($uid,$tdate);
    $taskData = $this->Menu_model->getTBLSCTaskByID($taskid);
    if (!empty($taskData) && isset($taskData[0]->initiated_datetime)) {
        $taskDatainit = $taskData[0]->initiated_datetime;
        if ($taskDatainit == '0000-00-00 00:00:00' || empty($taskDatainit)) {
            $initiateddttime = date("Y-m-d H:i:s");
            $this->db->set('initiated_datetime', $initiateddttime);
            $this->db->where('id', $taskid);
            $this->db->update('sc_task_events');
        }
    }
    $rquery      =  $this->db->query("SELECT * FROM `sc_task_request` WHERE taskid = '$taskid' AND cast(created_at as Date)= '$tdate'");
    $rqueryData  = $rquery->result();
    $this->load->view($dep_name.'/TeamDayBeforeTaskReviewCheckingInCRMApp',['uid'=>$uid,'user'=>$user,'getAllUserData'=>$getAllUserData,'sd'=>$tdate,'ctaskid'=>$taskid,'rqueryData'=>$rqueryData]);
}
