    $uid = $user['user_id'];
    $this->load->model('Menu_model');
    $this->load->library('session');
    if (strpos($timezone, "Todays Pending") !== false || strpos($timezone, "Old Pending") !== false) {
        $stequery      =  $this->db->query("SELECT * FROM `sc_task_events` WHERE id = '$taskid'");
        $stequeryData  = $stequery->result();
        $sc_task_id  = $stequeryData[0]->sc_task_id;
     
        $query      =  $this->db->query("SELECT * FROM `sc_task` WHERE id = '$sc_task_id'");
        $queryData  = $query->result();
        $queryDatacnt = sizeof($queryData);
        if($queryDatacnt > 0){
            $task_time  = $queryData[0]->task_time;
            if(is_null($task_time) || $task_time == '00:00:00'){
                echo 0;
            }else{
                echo $task_time;
            }
        }else{
            echo $queryDatacnt;
        }
    }else {
        $query      =  $this->db->query("SELECT * FROM `sc_task` WHERE id = '$taskid'");
        $queryData  = $query->result();
        $queryDatacnt = sizeof($queryData);
        if($queryDatacnt > 0){
            $task_time  = $queryData[0]->task_time;
            if(is_null($task_time) || $task_time == '00:00:00'){
                echo 0;
            }else{
                echo $task_time;
            }
        }else{
            echo $queryDatacnt;
        }
    }
}
