public function UpdateScTaskWithIdWithRemarksEmailSummaryShare(){
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           = $user['type_id'];
    $pdate          = date("Y-m-d");
    $taskid         = $this->input->post('taskid');
    $remarks        = $this->input->post('remarks');   
    unset($_POST["taskid"], $_POST["remarks"]);
    $emailjson_array = json_encode($_POST,true);
    $this->load->model('Menu_model');
    $this->load->library('session');
    $taskData = $this->Menu_model->getTBLSCTaskByID($taskid);
    $taskDatacnt = sizeof($taskData);
    if($taskDatacnt > 0){
        $taskData_status = $taskData[0]->status;
        if($taskData_status == 0){
            if (isset($_FILES['filname']) && !empty($_FILES['filname']['name'])) {
                $filnamecnt =  count($_FILES['filname']);
                $uploadPath = 'uploads/SCDailyActivity/';
                if (!is_dir($uploadPath)) {
                    mkdir($uploadPath, 0777, true);
                }
                $filename = $_FILES['filname']['name'];
                if($filnamecnt > 0){
                    $flink = $this->Menu_model->MultipleUploadFiles("filname", $uploadPath);
                    $flinkjson = json_encode($flink,true);
                    $attachment = $flinkjson;
                }else{
                    $attachment = 'NULL';
                }
            }else{
                $attachment = 'NULL';
            }
            
            $dt             = $this->Menu_model->get_utype($uyid);
            $dep_name       = $dt[0]->name;
           
            $updatedatetime = date("Y-m-d H:i:s");
            $data = array(
                'complete_datetime' => $updatedatetime,
                'remarks'           => $remarks,
                'attachment'        =>$attachment,
                'status'            => 1,
                'extra_remarks'     => $emailjson_array
            );
            
            $this->db->where('id',$taskid);
            $success = $this->db->update('sc_task_events', $data);
            if($success) {
            $this->session->set_flashdata('success_message','  Task Compleated !!');
            redirect('Menu/Dashboard');
            }
        }else{
            $this->session->set_flashdata('error_message','  Task Allready Compleated !!');
            redirect('Menu/Dashboard');
        }
    }else{
        $this->session->set_flashdata('error_message',' No Task Found !!');
        redirect('Menu/Dashboard');
    }
}
