public function StartAnnualReviews(){
    date_default_timezone_set("Asia/Calcutta");
    $tdate          = date('Y-m-d H:i:s');
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           = $user['type_id'];
    
    $this->load->model('Menu_model');
    $this->load->library('session');
    $dt             = $this->Menu_model->get_utype($uyid);
    $dep_name       = $dt[0]->name;
    $sarData        = $this->Menu_model->get_start_annual_review($uid);
    
    if(sizeof($sarData) > 0){
        $annual_statusid = $sarData[0]->company_status;
    }else{
        if(isset($_POST['annual_statusid'])){
            $annual_statusid = $this->input->post('annual_statusid');
            if($annual_statusid != 0){
           
                $data = array(
                    'uid'            => $uid ,
                    'company_status' => $annual_statusid,
                    'close_status'   => 'Pending',
                    'remarks'        => "Start Review"
                );
                $this->db->insert('start_annual_review', $data);
                $insert_id = $this->db->insert_id();
    
                // $start_date = $this->Menu_model->getFinancialYearRange(); 
                $start_date = $this->Menu_model->getCustmizeFinancialYear(); 
                $financial_year = (new DateTime($start_date['start_date']))->format('Y');
        
                $data = array(
                    'revew_id'     => $insert_id,
                    'user_id'      => $uid,
                    'revew_year'   => $financial_year,
                    'psdatetime'   => date("Y-m-d H:i:s"),
                    'pstime'       => date("H:i:s"),
                    'main_review_on'=>"ON"
                );
                // Insert data into the 'annual_review_session' table
                $this->db->insert('annual_review_session', $data);
                $sarData        = $this->Menu_model->get_start_annual_review($uid);
            }else{
                $this->session->set_flashdata('error_message',' * Please Select Specific Status');
            }
        }else{
            $annual_statusid = 0;
            $this->session->set_flashdata('success_message','* Annual Review');
            }
    }
    if(!empty($user)){
        // $this->load->view($dep_name.'/StartAnnualReviews',['uid'=>$uid,'dep_name'=>$dep_name,'user'=>$user,'annual_statusid'=> $annual_statusid,'sarData'=>$sarData]);
        $this->load->view('Functions/StartAnnualReviews',['uid'=>$uid,'dep_name'=>$dep_name,'user'=>$user,'annual_statusid'=> $annual_statusid,'sarData'=>$sarData]);
    }else{
        redirect('Menu/main');
    }
}





