public function getAnuualRevirewCmpOnReviewPage(){
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $cu_admin_id    = $user['admin_id'];
    $stid           = $this->input->post('stid');
    $type_id        =  $user['type_id'];

    $cmp_status_id  = $stid;


       $allowed_status = '';

        
       
     


    // $financial_Year_date = $this->Menu_model->getFinancialYearRange(); 
    $financial_Year_date    = $this->Menu_model->getCustmizeFinancialYear('current');
    $start_date             = $financial_Year_date['start_date'];
    $end_date               = $financial_Year_date['end_date'];
    $cfyear                 = date('Y', strtotime($start_date));
    // echo $start_date ." - ". $end_date;
    $cfyearFilter           = " AND amr.financial_year = $cfyear";
    $mainInituserFilter     = "";
    $userFilter             = "";
    $ststusFilter           = '';



    if($cmp_status_id == 0){

        if($type_id == 3){ 
            // BD Team
            $ststusFilter = " AND init_call.cstatus IN (1, 2, 8, 10, 11)"; 
        }
        elseif(in_array($type_id, [22, 24, 13, 4])){ 
            // RM, CM, PST, ACM
