public function GetCompanyQ1Closure(){
   
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           =  $user['type_id'];
    $inid           = $this->input->post('inid');
    $fdate          = $this->input->post('fdate');
    $this->load->model('Menu_model');
    $cmplogs = $this->Menu_model->GetCopmanyLogFrequencyInThisFinancialYear($inid);
    $cmpStatuslogs = $this->Menu_model->GetCopmanyStatusLogFrequencyInThisFinancialYear($inid);
    echo "<div class='bg-primary p-3'> <h6 class='text-center'>Task Frequency By Role </h6> </div>";
    $groupedTasks = [];
    foreach ($cmplogs as $task) {
        $groupedTasks[$task->task_user_id][] = $task;
    }
    echo "<input type='hidden' value='Average Task Frequency By Role ? ' name='task_frequency_by_user[]'>";
    foreach ($groupedTasks as $userId => $tasks) {
        $utypeData    = $this->Menu_model->get_userbyid($userId);
        $task_by_name = $utypeData[0]->name;
        $total_minutes = 0;
        $count = 0;
        foreach ($tasks as $task) {
            $user_type_name = $task->user_type_name;
          if ($task->frequency_between_plan) {
                // Initialize default values
                $days = 0;
                $hours = 0;
                $minutes = 0;
                
                // Extract time values from the frequency string
                preg_match('/(\d+)\s*days?/', $task->frequency_between_plan, $matches);
                if ($matches) $days = $matches[1];
                
                preg_match('/(\d+)\s*hours?/', $task->frequency_between_plan, $matches);
                if ($matches) $hours = $matches[1];
                
                preg_match('/(\d+)\s*minutes?/', $task->frequency_between_plan, $matches);
                if ($matches) $minutes = $matches[1];
                
                // Convert total time to minutes
                $total_time_in_minutes = ($days * 24 * 60) + ($hours * 60) + $minutes;
                
                // Add to total minutes
                $total_minutes += $total_time_in_minutes;
                $count++;
            }
        }
        if ($count > 0) {
            $average_minutes = $total_minutes / $count;
        
            // Convert back to hours and minutes
            $average_hours = floor($average_minutes / 60);
            $average_remaining_minutes = $average_minutes % 60;
        
            // Display the result
            $days = floor($average_hours / 24);
            $remaining_hours = $average_remaining_minutes % 24;
        
            // Output the result
            $taskfrequency = "Average Task Frequency By : $task_by_name ($user_type_name)= " . $days . " days " . $remaining_hours . " hours " . $average_remaining_minutes . " minutes";
            echo "<input type='hidden' value='$taskfrequency' name='task_frequency_by_user[]'>";
            echo "<div class='text-center p-2 frequencyboxcss'><h5>$taskfrequency</h5></div>";
        } else {
            echo "<input type='hidden' value='No Task Found' name='task_frequency[]'>";
            echo "<div class='text-center p-2 frequencyboxcss'><h5>No valid frequency data to calculate average.</h5></div>";
        }
    }
    echo "<hr>";
    // Start table output
    echo "<table class='table table-bordered'>";
    echo "<thead>";
    echo "<tr>";
    echo "<th scope='col'>#</th>";
    echo "<th scope='col'>Task Perform Name</th>";
    echo "<th scope='col'>Task Date</th>";
    echo "<th scope='col'>Action</th>";
    echo "<th scope='col'>Frequency Between Plan</th>";
    echo "<th scope='col'>Task Status</th>";
    echo "</tr>";
    echo "</thead>";
    echo "<tbody>";
    // Check if data exists
if (sizeof($cmplogs) > 0) {
    $i=1;
    foreach ($cmplogs as $cmplog) {
        echo "<tr>";
        echo "<td>" . $i . "</td>";
        echo "<td>" . $cmplog->task_by_name . "</td>";
        echo "<td>" . $cmplog->appointmentdatetime . "</td>";
        echo "<td>" . $cmplog->action_name . "</td>";
        echo "<td>" . $cmplog->frequency_between_plan . "</td>";
        echo "<td>" . $cmplog->task_status . "</td>";
        echo "</tr>";
        $i++;
    }
} else {
    // If no data, display this row
    echo "<tr><td colspan='4'>No data found</td></tr>";
}
// Close table
echo "</tbody>";
echo "</table>";
echo "<hr>";
echo "<div> <div class='bg-primary p-3'> <h6 class='text-center'>Status Frequency By Role </h6> </div>";
$groupedTasksData = [];
foreach ($cmpStatuslogs as $task) {
    $groupedTasksData[$task->task_user_id][] = $task;
}
echo "<input type='hidden' value='$taskfrequency' name='status_change_frequency_by_user[]'>";
foreach ($groupedTasksData as $userId => $tasks) {
