            if ($matches) $days = $matches[1];
            
            preg_match('/(\d+)\s*hours?/', $task->frequency_between_plan, $matches);
            if ($matches) $hours = $matches[1];
            
            preg_match('/(\d+)\s*minutes?/', $task->frequency_between_plan, $matches);
            if ($matches) $minutes = $matches[1];
            
            // Convert total time to minutes
            $total_time_in_minutes = ($days * 24 * 60) + ($hours * 60) + $minutes;
            
            // Add to total minutes
