            $count++;
        }
    }
    if ($count > 0) {
        $average_minutes = $total_minutes / $count;
    
        // Convert back to hours and minutes
        $average_hours = floor($average_minutes / 60);
        $average_remaining_minutes = $average_minutes % 60;
    
        // Display the result
