public function GetTravelClusterByBDID(){
    $type_id         = $_SESSION['user']['type_id'];
    $uid             = $_SESSION['user']['id'];
    $inid     = $_POST['inid'];
    $this->load->model('Menu_model');
    $this->load->library('session');
    $query = $this->db->query("SELECT * FROM `init_call` WHERE id = '$inid'");
    $cData =  $query->result();
    $mainbd = $cData[0]->mainbd;
    $cquery = $this->db->query("SELECT * FROM `cluster` WHERE user_id = '$mainbd'");
    $ccData =  $cquery->result();
    echo "<option value=''>Select</option>";
    if(sizeof($ccData) > 0){
        foreach($ccData as $cluster):
            echo "<option value='$cluster->id'>$cluster->clustername</option>";
        endforeach;
        if($uid !== $mainbd){
            echo "<option value='Suggest to change travel cluster'>Suggest to change travel cluster</option>";
        }
    }else{
        echo "<option value='Suggest to change travel cluster'>Suggest to change travel cluster</option>";
        echo "<option value='Suggest to add a travel cluster'>Suggest to add a travel cluster</option>";
    }
}
