public function SCAddAgreeDisagree(){ 
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           =  $user['type_id'];
    $this->load->model('Menu_model');
    $this->load->library('session');
    $amrid          = $this->input->post('amrid');
    $agree_diagree  = $this->input->post('agree_diagree');
    $remarks        = $this->input->post('remarks');
    $data = array(
        'review_apr_status' => $agree_diagree,
        'review_apr_by'     => $uid,
        'review_apr_remarks' =>$remarks
    );
    
    $this->db->where('id',$amrid);
    $success = $this->db->update('annual_main_review', $data);
    if($agree_diagree == 1){
        $this->session->set_flashdata('success_message',' Annual Review Agree SuccessFully ✅!!');
    }
    if($agree_diagree == 2){
        $this->session->set_flashdata('success_message',' Annual Review Disagree SuccessFully ✅!!');
    }
    redirect('Menu/CheckAnnualReviewDetailsReport/'.$amrid);
}
