public function trackActivity() {
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           =  $user['type_id'];
    $this->load->model('Menu_model');
    $eventType      = $this->input->post('eventType');
    $eventTime      = date("Y-m-d H:i:s");
    $urlPath        = $this->input->post('urlPath');
    $lastEventId    = $this->input->post('lastEventId');
   
    if ($eventType === 'open' || $lastEventId =='') {
        // Insert a new record for page open
        $data = array(
            'user_id' => $uid,
            'event_type' => $eventType,
            'event_time' => $eventTime,
            'url_path' => $urlPath
        );
        $this->db->insert('user_activity', $data);
        $eventId = $this->db->insert_id();
    } else {
        // Update the existing record with leave_time or return_time
        if ($lastEventId) {
            if ($eventType === 'leave' || $eventType === 'hidden') {
                $this->db->where('id', $lastEventId);
                $this->db->update('user_activity', array('leave_time' => $eventTime));
            } elseif ($eventType === 'return' || $eventType === 'visible') {
                if($eventType === 'return'){
                    $returnData = $this->Menu_model->getMostRecentRecordId($lastEventId);
                    $returnCount = $returnData[0]->return_count+1;
                    $this->db->where('id', $lastEventId);
                    $this->db->update('user_activity', array('return_count'=>$returnCount));
                }
                $this->db->where('id', $lastEventId);
                $this->db->update('user_activity', array('return_time' => $eventTime));
            } elseif ($eventType === 'closed') {
                $this->db->where('id', $lastEventId);
                $this->db->update('user_activity', array('leave_time' => $eventTime,'closed_event_type' => $eventType,'closed_event_time' => $eventTime));
            }
            $eventId = $lastEventId;
        }
    }
    echo json_encode(array('status' => 'success', 'eventId' => $eventId));



}
