public function GetTodaysPlannedTravelMeetingsData(){
    $user           =   $this->session->userdata('user');
    $data['user']   =   $user;
    $uid            =   $user['user_id'];
    $uyid           =   $user['type_id'];
    $tdate          = date("Y-m-d");
    $travelMeetindsDatas        =  $this->Menu_model->GetUserPlannedTravelMeetingsByUid($uid,$tdate);
    $travelMeetindsDatacnt      = sizeof($travelMeetindsDatas);
    $baseLocationMeetings       = 0;
    $outLocationMeetings        = 0;
    if($travelMeetindsDatacnt > 0){
        $result = [];
        foreach ($travelMeetindsDatas as $item) {
            $travelType = $item->travelType;
            $actiontype_id = $item->actiontype_id;
        
            if (!isset($result[$travelType])) {
                $result[$travelType] = [];
            }
        
            if (!isset($result[$travelType][$actiontype_id])) {
                $result[$travelType][$actiontype_id] = 0;
            }
            $result[$travelType][$actiontype_id] += $item->total_actions;
        }
        $baseSheduledMeetingCout        = $result['base'][3];
        $baseBargMeetingCout            = $result['base'][4];
        $outStationSheduledMeetingCout  = $result['outStation'][3];
        $outStationBargMeetingCout      = $result['outStation'][4];
    }else{
        $baseSheduledMeetingCout        = 0;
        $baseBargMeetingCout            = 0;
        $outStationSheduledMeetingCout  = 0;
        $outStationBargMeetingCout      = 0;
    }
    
  
}
