public function extractCmpidIds($array) {
    $cmpidIds = [];
    foreach ($array as $item) {
        if (isset($item[5])) {
            $cmpidIds[] = $item[5];
        }
    }
    return $cmpidIds;
}
public function filterFirstArray($firstArray, $cmpidIds) {
    $filteredArray = [];
    foreach ($firstArray as $item) {
        if (!in_array($item->cmpid_id, $cmpidIds)) {
            $filteredArray[] = $item;
        }
    }
    return $filteredArray;
}
