public function AddPendingMeetingRequest(){
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           =  $user['type_id'];
    $this->load->model('Menu_model');
    $this->load->library('session');
    $dt             = $this->Menu_model->get_utype($uyid);
    $dep_name       = $dt[0]->name;
    $tdate = date("Y-m-d");
    
    $task_ids       = $this->input->post('task_id');
    $request_date   = $this->input->post('request_date');
    $remarks        = $this->input->post('pendingMeetingRequestRemarks');
    $task_count     = $this->input->post('task_count');
    // $request_remarks= $this->input->post('request_remarks');
    $task_ids_string = implode(',', $task_ids);
    $remarks_string = implode(',', $remarks);


    if(empty($request_date)){
        $this->session->set_flashdata('error_message', '* Request Date is required.');
        redirect('Menu/Dashboard/');
    }
    if(empty($task_ids_string)){
        $this->session->set_flashdata('error_message', '* Please select at least one Task to send Request.');
        redirect('Menu/Dashboard/');
    }

  
    $data = [
        'user_uid'           => $uid,
        'request_date'       => $request_date,
        'request_task_count' => $task_count,
        'task_ids'           => $task_ids_string,
        'remarks'            => $remarks_string
    ];
    $this->db->insert('pending_meetings_request', $data);
    $insert_id = $this->db->insert_id();
    if($insert_id){

    if($uyid == 22){

        $rmdata = [
            'apr_by'            => $uid,
            'apr_status '       => 1,
            'apr_date'          => date("Y-m-d H:i:s"),
            'apr_remakrs'       => "Backend - Self Apprved By RM"
        ];
        $this->db->where('id', $insert_id);
        $this->db->update('pending_meetings_request', $rmdata);
    }

         $this->session->set_flashdata('success_message', '* Request Sended Successfully.');
    }else{
        $this->session->set_flashdata('error_message', '* Request Not Sended. Please Try Again');
    }
    redirect('Menu/GetOurOrTeamTodaysPendingMeetingsTask/'.$request_date);
}
