public function PendingMeetingsTaskRequestApproved(){
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           = $user['type_id'];
    $this->load->model('Menu_model');
    $this->load->library('session');
    $dt                 = $this->Menu_model->get_utype($uyid);
    $dep_name           = $dt[0]->name;
    $approveid          = $this->input->post('approveid');
    $approve_by         = $this->input->post('approve_by'); // Admin || Line Manager
    $approve_remarks    = $this->input->post('approve_remarks');
    $reqDatas           = $this->Menu_model->GetPendingMeetingsRequestByID($approveid);
    
    if($uyid == 3){
        $this->session->set_flashdata('error_message', '* You are Not Authorized To Approve This Request.');
        redirect('Menu/GetOurOrTeamTodaysPendingMeetingsTaskRequest/');
    }

    if($approve_by == 'Line Manager'){
        
        if(sizeof($reqDatas) > 0){

            if($reqDatas[0]->user_uid == $uid){
                $this->session->set_flashdata('error_message', '* You are Not Authorized To Approve Your Own Request.');
                redirect('Menu/GetOurOrTeamTodaysPendingMeetingsTaskRequest/');
            }   

            $udata1 = array(
                'apr_status'    => 1,
                'apr_by'        => $uid,
                'apr_date'      => date("Y-m-d H:i:s"),
                'apr_remakrs'   => $approve_remarks
            );
            $this->db->where('id', $approveid);
            $updated = $this->db->update('pending_meetings_request', $udata1);

            $this->session->set_flashdata('success_message', '* Line Manager Request Approved Successfully. Pending For Admin Approval.');

        }
    }else if($approve_by == 'Admin'){

        if(!in_array($uyid, [1,2])){
            $this->session->set_flashdata('error_message', '* You are Not Authorized To Approve This Request.');
            redirect('Menu/GetOurOrTeamTodaysPendingMeetingsTaskRequest/');
        }

        if(sizeof($reqDatas) > 0){

            $taskids        = $reqDatas[0]->task_ids;
            $request_date   = $reqDatas[0]->request_date;
            $requestRemarksarrays = explode(",", $reqDatas[0]->remarks);
            $getTaskReqLists = $this->Menu_model->GetTblCallEventsTasksList($taskids);
            $l = 0;

            foreach ($getTaskReqLists as $value){

                $callEventId            = $value->task_id;
                $nextCFID               = $value->nextCFID;
                $remark                 = $requestRemarksarrays[$l];

                if($nextCFID == 0){

                    $company_cid        = $value->cid;
                    $company_name       = $value->company_name; // Unknown
                    $init_call_id       = $value->init_call_id;
                    $task_mtype         = $value->mtype;
                    $cash_allot         = $value->cash_allot;
                    $meeting_task_uid   = $reqDatas[0]->user_uid;
                    $cash_allot         = !empty($cash_allot) ? $cash_allot : 0;
 
                    $cudetail           = $this->Menu_model->get_userbyid($meeting_task_uid);
                    $current_user_cash  = $cudetail[0]->ucash;

                    if($cash_allot > 0){
                        
