    $uyid           =  $user['type_id'];
    if (empty($user)){redirect('Menu/main');}
    if(in_array($uyid,[13,4,22,23])){
       
    $this->load->model('Menu_model');
    $this->load->library('session');
    $dt             = $this->Menu_model->get_utype($uyid);
    $dep_name       = $dt[0]->name;
    $state          = $this->Menu_model->GetState();
    $totalTeams     = $this->Menu_model->GetTotalTeam($uid);
    $this->load->view('Functions/CreateTravelCluster',['uid'=>$uid,'user'=>$user,'comming_user_types'=>$uyid,'dep_name'=>$dep_name,'state'=> $state,'totalTeams'=>$totalTeams]);
