   public function UpdateUserCluster(){
        $user           = $this->session->userdata('user');
        $data['user']   = $user;
        $uid            = $user['user_id'];
        $uyid           =  $user['type_id'];
        $this->load->model('Menu_model');
   
        $travelId               = $this->input->post('travelId');
        $typeofTravel           = $this->input->post('typeofTravel');
        $cluster_name           = $this->input->post('cluster');
        $clusterState           = $this->input->post('clusterState');
        $clusterDistrict        = $this->input->post('clusterDistrict');
        $clusterCity            = $this->input->post('clusterCity');
        $cluster_reamrks        = $this->input->post('cluster_reamrks');
        $implodeClusterDistrict = implode(",", $clusterDistrict);
        $implodeClusterCity     = implode(",", $clusterCity);
      
        $data = array(
            'clustername'   => "$cluster_name",
            'in_state'      => $clusterState,
            'in_district'   => "$implodeClusterDistrict",
            'in_city'       => "$implodeClusterCity",
            'travelType'    => "$typeofTravel",
            'bd_reamrks'    => "$cluster_reamrks"
            // 'apr_status'    => 0,
            // 'apr_by'        => NULL
        );
        $this->db->where('id', $travelId); 
        $this->db->update('cluster', $data);
       
        $this->load->library('session');
        $this->session->set_flashdata('success_message', '* Travel Cluster Record Updated successfully');
        redirect('Menu/TravelClusterDetails');
    }
