    if(sizeof($earlydata) > 0){
        $request_uid        = $earlydata[0]->user_id;
        $request_date       = $earlydata[0]->request_date;
        $request_new_time   = $earlydata[0]->new;
        $userAutoTaskDatas  =  $this->Menu_model->ChekPlannerStartSetOrNot($request_uid,$request_date);
        if(sizeof($userAutoTaskDatas) > 0){
              $userAutotaskTimeId =  $userAutoTaskDatas[0]->id;
               $atdata = array(
                    'start_tttpft' => $request_new_time.':00'
                );
                $this->db->where('id', $userAutotaskTimeId);
                $at_updated = $this->db->update('autotask_time', $atdata);
                if ($at_updated){
                      $data = array(
                            'approved_status' => $action_status,
                            'approved_by'     => $uid,  
                            'approved_date'   => $approved_date
                        );
                        $this->db->where('id', $action_id);
