public function ChangeCompanyStatus(){
    $user           = $this->session->userdata('user');
    $uid            = $user['user_id'];
    $data['user']   = $user;
    $user_id        = $user['user_id'];
    $this->load->model('Menu_model');
    $this->load->library('session');
    $company_id        = $this->input->post('company_id');
    $changestatus      = $this->input->post('changestatus');
    $cdatas = $this->Menu_model->getCompanyStatus($company_id);
    if(sizeof($cdatas) > 0){
        $init_id = $cdatas[0]->id;
        $cstatus = $cdatas[0]->cstatus;
        $lstatus = $cdatas[0]->lstatus;
        $data = array(
            'cstatus' => $changestatus,
            'lstatus' => $cstatus
        );
        $this->db->where('cmpid_id', $company_id);
        $this->db->update('init_call', $data);
                $data = array(
                    'init_id'      => $init_id,
                    'cid'          => $company_id,
                    'old_status'   => $cstatus,
                    'new_status'   => $changestatus,
                    'update_by'    => $uid
                );
              $this->db->insert('company_log', $data);
       if ($this->db->affected_rows() > 0) {
            $message =  "* Status change successfully.";
            $variable =  "success_message";
        } else {
            $message =  "* Status no changes .";
            $variable =  "error_message";
        }
    }
    $this->session->set_flashdata($variable,$message);
    redirect('Menu/CompanyDetails/'.$company_id);
}
