        $query      =  $this->db->query("SELECT * FROM `categories`");
        $userDatas  =  $query->result();
        $k=1;
        foreach($userDatas as $catData){
            if($catData->dataname == 'upsell_client'){
                    $yesChecked = $upsell_client === "yes" ? "checked" : "";
                    $noChecked  = ($upsell_client === "no"  ||  $upsell_client === NULL)? "checked" : "";
            }else if($catData->dataname == 'focus_funnel'){
                    $yesChecked = $focus_funnel === "yes" ? "checked" : "";
                    $noChecked  = ($focus_funnel === "no"  ||  $focus_funnel === NULL)? "checked" : "";
            }else if($catData->dataname == 'keycompany'){
                    $yesChecked = $keycompany === "yes" ? "checked" : "";
                    $noChecked  = ($keycompany === "no"  ||  $keycompany === NULL)? "checked" : "";
            }else if($catData->dataname == 'pkclient'){
                    $yesChecked = $pkclient === "yes" ? "checked" : "";
                    $noChecked  = ($pkclient === "no"  ||  $pkclient === NULL)? "checked" : "";
            }else if($catData->dataname == 'priorityc'){
                    $yesChecked = $priorityc === "yes" ? "checked" : "";
                    $noChecked  = ($priorityc === "no"  ||  $priorityc === NULL)? "checked" : "";
            }else if($catData->dataname == 'topspender'){
                    $yesChecked = $topspender === "yes" ? "checked" : "";
                    $noChecked  = ($topspender === "no"  ||  $topspender === NULL)? "checked" : "";
            }else{
                    $yesChecked = "";
                    $noChecked  = "";
            }
          
            echo '
            <h5>'.$catData->name.'</h5>
            <div class="form-check">
                    <input class="form-check-input" type="radio" name="'.$catData->dataname.'" id="'.$catData->dataname.'_1" '.$yesChecked.' value="yes">
                    <label class="form-check-label" for="'.$catData->dataname.'_1">
                        Yes
                    </label>
                &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
                    <input class="form-check-input" type="radio" name="'.$catData->dataname.'" id="'.$catData->dataname.'_2" '.$noChecked.' value="no">
                    <label class="form-check-label" for="'.$catData->dataname.'_2">
                       No
                    </label>
                </div> <hr>';
                $k++;
            }
        }
    }else if($clicked_text == 'Financial Year Category'){
        $curFinancialDate           = $this->Menu_model->getFinancialYearRange();
        $start_financial_date       = $curFinancialDate['start_date'];
        $start_financial_date_year  = new DateTime($start_financial_date);
        $fyear                      = $start_financial_date_year->format('Y');
       
