        $potential_funnel_for_fy    = $cdatas[0]->potential_funnel_for_fy;
        $to_be_nurtured_for_fy      = $cdatas[0]->to_be_nurtured_for_fy;
        $fifity_new_lead_funnel     = $cdatas[0]->fifity_new_lead_funnel;
       if($q1_twetenty_closure_funnel == $fyear){
            echo "<b>Q1 20 Closure Funnel :</b> $q1_twetenty_closure_funnel <br/>";
