                    <option value="potential_funnel_for_fy" ' . ($potential_funnel_for_fy == $fyear ? 'selected' : '') . '>Potential Funnel For FY</option>
                    <option value="to_be_nurtured_for_fy" ' . ($to_be_nurtured_for_fy == $fyear ? 'selected' : '') . '>To be Nurtured for FY</option>
                    <option value="fifity_new_lead_funnel" ' . ($fifity_new_lead_funnel == $fyear ? 'selected' : '') . '>50 New Lead Funnel</option>
                </select>
            </div>
            <hr>';
    }
    else if($clicked_text == 'Current Quarter Category'){
        
        $cfData                = $this->Menu_model->getCurrentFinancialYearAndQuarter();
        // echo "Financial Year: " . $result['financial_year'] . "\n";
