        $checkLeaveExistsOrNot  = $this->Menu_model->CheckAddLeaveByZoneAndDate($leave_zone,$leave_sdate,$leave_edate);
        if(sizeof($checkLeaveExistsOrNot) == 0){
        $data = [
                'leave_name'                => $holiday_name,
                'leave_type'                => $title_message,
                'leave_sdate'               => $leave_sdate,
                'leave_edate'               => $leave_edate,
                'leave_reson'               => 'Full Day '.$title_message,
                'leave_zone'                => $leave_zone,
                'leave_by'                  => $uid,
                'add_type'                  => 'Manual', 
                'leave_apr_by'              => $uid, 
                'leave_apr_date'            => date("Y-m-d H:i:s"),
                'leave_apr_status'          => 1,
                'leave_apr_by_admin'        => $uid, 
                'leave_apr_date_by_admin'   => date("Y-m-d H:i:s"),
                'leave_apr_status_by_admin' => 1
            ];
            $this->db->insert('leave_management', $data);
            if ($this->db->affected_rows() > 0) {
                $variable   =  "success_message";
                $message    = "* $title_message for the $leave_zone on $leave_sdate - $leave_edate has apply successfully! ✅";
            } else {
                $variable   =  "error_message";
                $message    = "* Failed to add $title_message for the $leave_zone on $leave_sdate - $leave_edate";
            }
        }else{
            if($leave_zone == 'all'){
                $leave_zone = 'all zone';
            }else{
                $leave_zone = $this->Menu_model->GetAllZoneDatasByID($leave_zone)[0]->name;
            }
            $variable =  "error_message";
            $message  = "* $title_message for the $leave_zone on $leave_sdate - $leave_edate has already been apply! ✅";
        }
    }else if($byusername == 'by_user'){
        $leave_reson            = $this->input->post('leave_reson');
        $title_message          = 'Leave';
        $checkLeaveExistsOrNot  = $this->Menu_model->CheckAddLeaveByUserAndDate($uid,$leave_sdate,$leave_edate);
        if(sizeof($checkLeaveExistsOrNot) == 0){
        $udetail        = $this->Menu_model->get_userbyid($uid); 
        $leave_zone     = $udetail[0]->zone_id;
         $data = [
                'leave_name'      => $title_message,
                'leave_type'      => $title_message,
                'leave_sdate'     => $leave_sdate,
                'leave_edate'     => $leave_edate,
                'leave_reson'     => $leave_reson,
                'leave_zone'      => $leave_zone,
                'leave_by'        => $uid,
                'add_type'        => 'Manual', 
            ];
            $this->db->insert('leave_management', $data);
            $insert_id = $this->db->insert_id();
            if ($insert_id) {
                if(in_array($uyid,[18,19,20,21,23,15])){
                    $dataapr = array(
                        'leave_apr_by'              => $uid, 
                        'leave_apr_date'            => date("Y-m-d H:i:s"),
                        'leave_apr_status'          => 1
                    );
                    $this->db->where('id', $insert_id);
                    $this->db->update('leave_management', $dataapr);
                }
                 $variable  =  "success_message";
                 $message   = "* $title_message on the $leave_sdate - $leave_edate apply successfully! ✅";
            } else {
                $variable   =  "error_message";
                $message    = "* Failed to add $title_message on the $leave_sdate - $leave_edate";
            }
        }else{
            $variable       =  "error_message";
            $message        = "* $title_message on the $leave_sdate - $leave_edate has already apply added! ✅";
        }
    }
    $this->session->set_flashdata($variable,$message);
    redirect('Menu/LeaveManagement');
}
public function ApproveByLineManager(){
