    $approved_status    = $this->input->post('ApproveByLineManager');
    if($approved_status == ''){
        $variable   =  "error_message";
        $message    = "* Approved status can not be empty.";
        $this->session->set_flashdata($variable,$message);
        redirect('Menu/LeaveManagement');
    }
    if($approved_status == 1){
        $title_message = 'Approved';
    }else if($approved_status == 2){
        $title_message = 'Rejected';   
    }
    if($approveby == 'Line Manager'){
          $data = array(
                'leave_apr_by'              => $uid, 
                'leave_apr_date'            => date("Y-m-d H:i:s"),
                'leave_apr_status'          => $approved_status
            );
            $this->db->where('id', $approveid);
            $this->db->update('leave_management', $data);
            if ($this->db->affected_rows() > 0) {
                $variable   =  "success_message";
                $message    = "* Leave $title_message Successfully.";
            } else {
                $variable   =  "error_message";
                $message    = "* Leave Failed to $title_message .";
            }
    }else if($approveby == 'Admin'){
        
           $data = array(
                'leave_apr_by_admin'        => $uid, 
                'leave_apr_date_by_admin'   => date("Y-m-d H:i:s"),
                'leave_apr_status_by_admin' => $approved_status
            );
            $this->db->where('id', $approveid);
            $this->db->update('leave_management', $data);
            if ($this->db->affected_rows() > 0) {
                $variable   =  "success_message";
                $message    = "* Leave $title_message Successfully.";
            } else {
                $variable   =  "error_message";
                $message    = "* Leave Failed to $title_message .";
            }
    }
   
$this->session->set_flashdata($variable,$message);
redirect('Menu/LeaveManagement');
}
