public function CheckDaysCheckPendingByUser(){
    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           =  $user['type_id'];
    $this->load->model('Menu_model');
    $this->load->library('session');
    $currentDate    = date("Y-m-d");
    $checkDate      =  $this->Menu_model->findSpecialDate($currentDate);
    $completeUID    =  $this->Menu_model->CheckUserDayCheckCompleteOrNot($uid,$checkDate);
    
    $ourTeamUID     =  $this->Menu_model->CheckTeamMappingsDatas($uid,$checkDate);
        $names1 = array_map(function($obj) {
            return $obj->name;
        }, $completeUID);
        // Filter array2
        $array3 = array_filter($ourTeamUID, function($obj) use ($names1) {
            return !in_array($obj->name, $names1);
        });
        // Re-index array
        $array3 = array_values($array3);
        $names = array_map(function($obj) {
            return $obj->name;
        }, $array3);
        $namelists =  implode(", ", $names);
        $result = [
            'pending'   => sizeof($array3),
            'username'  => $namelists
        ];
        return $result;
}
