    if($bdrid){
        $fwd_date           = date("Y-m-d H:i:s");
        $task_action        = 22;   // Maintenance  -  Call (Pre-maintenance check-list From)
        $aftertask          = '';
        $call_visit         = 'DIY';
        $generate_task_id   = $this->Menu_model->CreateInaugurationTaskAfterBDRequest($task_action,$sales_cid,$bdrid,$fwd_date,$targetd,$remark,$sid,$call_visit,$aftertask,$pcode);

        $task_action        = 23;   // Maintenance  -  Visit (During--maintenance check-list From)
        $aftertask          = $generate_task_id;
        $generate_task_id   = $this->Menu_model->CreateInaugurationTaskAfterBDRequest($task_action,$sales_cid,$bdrid,$fwd_date,$targetd,$remark,$sid,$call_visit,$aftertask,$pcode);

        $task_action        = 24;   // Maintenance - Upload Maintenance Report
        $aftertask          = $generate_task_id;
        $generate_task_id   = $this->Menu_model->CreateInaugurationTaskAfterBDRequest($task_action,$sales_cid,$bdrid,$fwd_date,$targetd,$remark,$sid,$call_visit,$aftertask,$pcode);

        // $task_action        = 25;   // Maintenance - Call (Post - intervention maintenance by ZM)
        // $aftertask          = $generate_task_id;
        // $generate_task_id   = $this->Menu_model->CreateInaugurationTaskAfterBDRequest($task_action,$sales_cid,$bdrid,$fwd_date,$targetd,$remark,$sid,$call_visit,$aftertask,$pcode);

    }

        $completedatetime = date("Y-m-d H:i:s");

        // Update special_bdrequest_task
        $this->db->where('task_id', $req_taskid);
        $this->db->update('special_bdrequest_task', ['status' => '1']);
        
        // Update tblcallevents
        $data = [
            'actontaken'            => 'yes',
            'purpose_achieved'      => 'yes',
            'nextCFID'              => $req_taskid,
            'updateddate'           => $completedatetime,
            'updation_data_type'    => 'complete',
            'updated_at'            => $completedatetime
        ];
        
        $this->db->where('id', $req_taskid);
        $this->db->update('tblcallevents', $data);
        
        // Set success message and redirect
        $this->session->set_flashdata('success_message', 'School Maintenance BD request sent successfully.');
        redirect('Menu/Dashboard');

}

