            $proposal_to_be_sent_review = $cmp->proposal_to_be_sent_review;
            $proposal_to_be_sent_target = $cmp->proposal_to_be_sent_target;
            $closure_pipeline_october   = $cmp->closure_pipeline_october;

            $total_rp_meeting_done      = $cmp->total_rp_meeting_done;
            $pending_for_meeting        = $cmp->pending_for_meeting;
            $proposal_sent              = $cmp->proposal_sent;
            $pending_proposal_sent      = $cmp->pending_proposal_sent;
            $total_closure              = $cmp->total_closure;
            $total_pending_closure      = $cmp->total_pending_closure;

            $descriptions = array(
