public function ValidateEmailOrSent()
{

    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['user_id'];
    $uyid           =  $user['type_id'];

    $this->load->model('Menu_model');

    // Load upload library
    $this->load->library('upload');

    // Prepare response array
    $response = [];

    // Get text fields
    $email_task_id          = $this->input->post('email_task_id');
    $email_task_remarks     = $this->input->post('email_task_remarks');

 

    $uploadPath = FCPATH . 'uploads/email_screenshots/'; // FCPATH ensures full server path
    if (!is_dir($uploadPath)) {
        mkdir($uploadPath, 0777, true); // recursive folder creation
    }

    // File upload config
    $config['upload_path']   = $uploadPath; // make sure folder exists
    $config['allowed_types'] = 'jpg|jpeg|png|pdf';
    $config['max_size']      = 2048; // 2MB
    $config['file_name']     = uniqid('email_'); // unique filename prefix

    // Initialize config
    $this->upload->initialize($config);

    // Check if file is uploaded
    if (!empty($_FILES['formFile']['name'])) {
        if ($this->upload->do_upload('formFile')) {
            $uploadData = $this->upload->data();
            $fileName   = $uploadData['file_name'];
            $filePath   = base_url('uploads/email_screenshots/' . $fileName);

            // Example: insert into DB if needed
            $data = [
                'task_id'       => $email_task_id,
                'remark'        => $email_task_remarks,
                'file_name'     => $fileName,
                'file_path'     => $filePath,
                'validate_by'   => $uid,
                'validate_date' => date("Y-m-d H:i:s"),
                'created_at'    => date('Y-m-d H:i:s')
            ];

            $this->db->insert('email_validation_log', $data);

            $tbldata = [
                'attech'        => $filePath,
                'rremark'       => $email_task_remarks,
                'rby'           => $uid,
            ];
            $this->db->where('id', $email_task_id);
            $this->db->update('tblcallevents', $tbldata);

            
            $response = [
                'status'    => 'success',
                'message'   => 'Validate File uploaded successfully!',
                'file_name' => $fileName,
                'file_url'  => $filePath
            ];
        } else {
            $response = [
                'status'  => 'error',
                'message' => $this->upload->display_errors()
            ];
        }
    } else {
        $response = [
            'status'  => 'error',
            'message' => 'No file selected!'
        ];
    }

    // Return JSON response
    echo json_encode($response);
}


