        $cuser_id           = $this->input->post('user_id');
        $password           = $this->input->post('password');
        $confirmPassword    = $this->input->post('confirmPassword');

        if($cuser_id == $uid){

                if($password == $confirmPassword){
                    $userArr = array(
                    'fname'         => $this->input->post('fname'),
