public function GetAllAttchementDownload(){
        $user           = $this->session->userdata('user');
        $data['user']   = $user;
        $uid            = $user['id'];
        $id             =  $user['dep_id'];
        $this->load->model('Menu_model');
        $this->load->library('session');
        $this->load->library('zip');

        $stype = $this->input->get('stype');
        $value = $this->input->get('value');

        $this->load->database();
        $this->load->helper('download');
        $this->load->library('zip');
        

        $getFyearStartDate = $this->Menu_model->getFinancialYearRange()['start_date'];

        $fyear = date('Y', strtotime($getFyearStartDate));

        $taskStatus = "tblc.nextCFID != 0";

        if($stype =='task_id'){
            $filter = "AND tblc.id = '$value'";
        }else{
             
            $this->session->set_flashdata('error_message'," * Direct Script Not Allowed!");
             if(isset($_SERVER['HTTP_REFERER'])){
                  echo "<script>
                    window.location.href = '{$_SERVER['HTTP_REFERER']}';
                </script>";
                exit; // stop further PHP execution
            } else {
                redirect('Menu/Dashboard'); // fallback
            }
        }


  

        $query = $this->db->query("SELECT
            tblc.id as task_id,
            tblc.actontaken,
            tblc.purpose_achieved,
            tblc.remarks,
            a1.name as taskname,
            main_task.taskdetails,
            ted.task_response,
            tblach.attachment_link,
            company_master.compname,
            company_master.id AS cid
        FROM
            `tblcallevents` as tblc
        LEFT JOIN action a1 ON a1.id = tblc.actiontype_id
        LEFT JOIN init_call ON init_call.id = tblc.cid_id
        LEFT JOIN company_master ON company_master.id = init_call.cmpid_id

        LEFT JOIN task_execution_details ted ON ted.tbe_id = tblc.id
        LEFT JOIN main_task ON main_task.id = ted.main_task_id
        LEFT JOIN tblcallevents_attachments tblach ON tblach.id = ted.tbe_attachment_id
        WHERE
            $taskStatus $filter
                ");


if ($query->num_rows() > 0) {
    foreach ($query->result() as $row) {
        if (!empty($row->attachment_link)) {
            // remove base_url and get relative file path
            $file_path = str_replace(base_url(), FCPATH, $row->attachment_link);

            $folderName = $row->compname.'('.$row->cid.')';
            
            if (file_exists($file_path)) {
                // ✅ Add to zip inside folder named by SID
                $this->zip->read_file($file_path, $folderName . '/' . basename($file_path));
            }
        }
    }

    // Download zip
    $this->zip->download('attachments_file_' . $stype . '.zip');
} else {
    echo "⚠️ No attachments found.";
    $this->session->set_flashdata('error_message', " * ⚠️ No attachments found.");
}

       if(isset($_SERVER['HTTP_REFERER'])){
        
            echo "<script>
                window.location.href = '{$_SERVER['HTTP_REFERER']}';
            </script>";
            exit; // stop further PHP execution
        } else {
            redirect('Menu/Dashboard'); // fallback
        }
    }



public function ValidateEmailOrSentByUser()
    {

        $user           = $this->session->userdata('user');
        $data['user']   = $user;
        $uid            = $user['user_id'];
        $uyid           =  $user['type_id'];

        $this->load->model('Menu_model');
         $this->load->library('session');
        // Load upload library
        $this->load->library('upload');

        // Prepare response array
        $response = [];

        // Get text fields
        $task_user_id          = $this->input->post('task_user_id');
        $task_user_date          = $this->input->post('task_user_date');
        $email_task_remarks     = $this->input->post('email_task_remarks');

    
        $uploadPath = FCPATH . 'uploads/email_screenshots/'; // FCPATH ensures full server path
        if (!is_dir($uploadPath)) {
            mkdir($uploadPath, 0777, true); // recursive folder creation
        }

        // File upload config
        $config['upload_path']   = $uploadPath; // make sure folder exists
        $config['allowed_types'] = 'jpg|jpeg|png|pdf';
        $config['max_size']      = 2048; // 2MB
        $config['file_name']     = uniqid('email_'); // unique filename prefix

        // Initialize config
        $this->upload->initialize($config);

        // Check if file is uploaded
        if (!empty($_FILES['formFile']['name'])) {
            if ($this->upload->do_upload('formFile')) {
                
                $uploadData = $this->upload->data();
                $fileName   = $uploadData['file_name'];
                $filePath   = base_url('uploads/email_screenshots/' . $fileName);

                $data = [
                    'task_date'          => $task_user_date,
                    'task_user_id'       => $task_user_id,
                    'validate_attachment'=> $filePath,
                    'validate_by'        => $uid,
                    'validate_date'      => date("Y-m-d H:i:s"),
                    'remark'             => $email_task_remarks,
                    'created_at'         => date('Y-m-d H:i:s')
                ];
                $this->db->insert('email_validate', $data);
                $this->session->set_flashdata('success_message', " * Email Validated SuccessFully.");

        } else {
              $this->session->set_flashdata('error_message', " * ⚠️ Email Validation Failed !.");
        }

        redirect('Menu/TeamEmailTaskCheckNew'); // fallback

    }

}
