public function SubmitCALLOnSchool() {

    $user           = $this->session->userdata('user');
    $data['user']   = $user;
    $uid            = $user['id'];
    $id             =  $user['dep_id'];
    $this->load->model('Menu_model');
    $this->load->library('session');
    $db3                        = $this->load->database('db3', TRUE);

    // Get form data
    $taskId = $this->input->post('taskId');
    $taskType = $this->input->post('taskType');
    $main_task_id = $this->input->post('main_task_id');
    $action_completed = $this->input->post('action_completed');
    $purpose_completed = $this->input->post('purpose_completed');
    $main_task_remarks = $this->input->post('main_task_remarks');
    
    // Get JSON data
    $questionnaire_json = $this->input->post('questionnaire_json');
    
    // Get school ID from task
    $taskDetails = $this->Menu_model->getTBLTaskBySingleID($taskId);
    $sid = $taskDetails[0]->sid;


    $jsonData = json_decode($questionnaire_json, true);


    
        /* ========== SHORTCUT REFERENCES ========== */
        $meta   = $jsonData['metadata'];
        $call   = $jsonData['call_status']['questions'];
        $msc    = $jsonData['msc_questionnaire']['questions'];

        /* ========== PREPARE INSERT ARRAY ========== */
        $insertOpps = [

            // Metadata
            'sales_task_id'          => $meta['task_id'] ?? null,
            'school_id'              => $meta['school_id'] ?? null,
            'school_name'            => $meta['school_name'] ?? null,
            'submission_date'        => date('Y-m-d H:i:s', strtotime($meta['submission_date'] ?? date('Y-m-d H:i:s'))),
            'questionnaire_version'  => $meta['questionnaire_version'] ?? null,

            // Call status
            'action_completed'       => $call[0]['answer'] ?? null,
            'purpose_completed'      => $call[1]['answer'] ?? null,
            'final_remarks'          => $call[2]['answer'] ?? null,

            // Q1
            'spoc_details_correct'   => $msc[0]['answer'] ?? null,
            'spoc_name'              => $msc[0]['follow_up_questions'][0]['answer'] ?? null,
            'spoc_mobile'            => $msc[0]['follow_up_questions'][1]['answer'] ?? null,
            'spoc_email'             => $msc[0]['follow_up_questions'][2]['answer'] ?? null,
            'spoc_designation'       => $msc[0]['follow_up_questions'][3]['answer'] ?? null,
            'spoc_other_designation' => $msc[0]['follow_up_questions'][4]['answer'] ?? null,

            // Q2
            'msc_awareness'          => $msc[1]['answer'] ?? null,
            'msc_established_when'   => $msc[1]['follow_up_questions'][0]['answer'] ?? null,
            'msc_established_other'  => $msc[1]['follow_up_questions'][1]['answer'] ?? null,

            // Q3–Q10
            'msc_usage_teaching'     => $msc[2]['answer'] ?? null,
            'whatsapp_media_frequency'=> $msc[3]['answer'] ?? null,
            'utilization_count'      => $msc[4]['answer'] ?? null,

            'infrastructure_available'=> $msc[5]['answer'] ?? null,
            'available_infrastructure'=> $msc[5]['follow_up_questions'][0]['answer'] ?? null,

            'msc_current_condition'  => $msc[6]['answer'] ?? null,
            'maintenance_required'   => $msc[7]['answer'] ?? null,
            'teacher_training_required'=> $msc[8]['answer'] ?? null,
            'coordinator_final_remarks'=> $msc[9]['answer'] ?? null,
        ];

        /* ========== INSERT ========== */
         $db3->insert('msc_call_reports', $insertOpps);


    // Get current user ID
    $user_id = $this->session->userdata('user_id');
    
    // Decode JSON to validate
    $questionnaire_data = json_decode($questionnaire_json, true);
    
    if(json_last_error() !== JSON_ERROR_NONE) {
        $this->session->set_flashdata('error', 'Invalid questionnaire data format.');
        redirect($_SERVER['HTTP_REFERER']);
        return;
    }
    
    // Prepare data for insertion
    $data = array(
        'task_id'               => $taskId,
        'task_type'             => $taskType,
        'main_task_id'          => $main_task_id,
        'school_id'             => $sid,
        'action_completed'      => $action_completed,
        'purpose_completed'     => $purpose_completed,
        'main_task_remarks'     => $main_task_remarks,
        'questionnaire_data'    => $questionnaire_json,
        'submitted_by'          => $user_id,
        'submitted_at'          => date('Y-m-d H:i:s')
    );
    
    // Insert into database
    $this->db->insert('school_call_questionnaires', $data);
    $insert_id = $this->db->insert_id();


    if($insert_id) {
        // Update task status
       
        $data = array(
            'updateddate'       => date("Y-m-d H:i:s"),
            'actontaken'        => $actiontaken,
            'purpose_achieved'  => $purpose_achoved,
            'remarks'           => "$main_task_remarks",
            'special_remarks'   => "$questionnaire_json",
            'nextCFID'          => $taskId
        );
        $this->db->where('id', $taskId);
        $this->db->update('tblcallevents', $data);
        
        $this->session->set_flashdata('success', 'Questionnaire submitted successfully!');
        redirect('Menu/Dashboard');

    } else {
        $this->session->set_flashdata('error', 'Failed to submit questionnaire.');
        redirect('Menu/Dashboard');
    }
}

public function UpdateMarkedNeedToBeMonitored(){


    $this->load->model('Menu_model');
    $this->load->library('session');

    $user                       = $this->session->userdata('user');
    $uid                        = $user['user_id'];
    $data['user']               = $user;
    $user_id                    = $user['user_id'];
    $company_id                 = $this->input->post('company_id');
    $need_to_be_monitored       = $this->input->post('need_to_be_monitored');
    $cdatas                     = $this->Menu_model->getCompanyStatus($company_id);

    if($need_to_be_monitored == ''){
        $this->session->set_flashdata('error_message'," * No Change in Need to Be Monitored Status.");
        redirect('Menu/CompanyDetails/'.$company_id);
    }

    if(sizeof($cdatas) > 0){

        $init_id                    = $cdatas[0]->id;
        $old_need_to_be_monitored   = $cdatas[0]->need_to_be_monitored;

        if($need_to_be_monitored == 1){

            $need_to_be_monitored_text = " Marked as Need to Be Monitored.";
            $initData = array(
                'need_to_be_monitored' => "Need to Be Monitored"
            );
            $this->db->where('cmpid_id', $company_id);
            $this->db->update('init_call', $initData);

        }else if ($need_to_be_monitored == 0){

            $need_to_be_monitored_text = " Removed from Need to Be Monitored.";
            $initData = array(
                    'need_to_be_monitored' => NULL
                );
            $this->db->where('cmpid_id', $company_id);
            $this->db->update('init_call', $initData);

        }

        if(is_null($old_need_to_be_monitored) OR empty($old_need_to_be_monitored)){
            $old_need_to_be_monitored = " Not in Need to Be Monitored.";
        }

                $data = array(
                    'init_id'      => $init_id,
                    'cid'          => $company_id,
                    'old_need_to_be_monitored'   => "$old_need_to_be_monitored",
                    'new_need_to_be_monitored'   => "$need_to_be_monitored_text",
                    'update_by'    => $uid
                );
              $this->db->insert('company_log', $data);

       if ($this->db->affected_rows() > 0) {
            $message =  "* * Company Set in Need to Be Monitored successfully.";
            $variable =  "success_message";
        } else {
            $message =  "* * Company Remove Monitoring successfully .";
            $variable =  "error_message";
        }
    }
    $this->session->set_flashdata($variable,$message);
    redirect('Menu/CompanyDetails/'.$company_id);
}




