            return;
        }

        $this->load->model('Menu_model');
        $cities = $this->Menu_model->search_cities_by_name($search);

        $options = '<option value="">Select City</option>';
        foreach ($cities as $city) {
            // Adjust property names according to your DB table
            $options .= '<option value="' . $city->name . '">' . htmlspecialchars($city->name) . '</option>';
        }

        echo json_encode([
            'status'  => 'success',
            'count'   => count($cities),
            'options' => $options
        ]);
    }



