  public function PreIdentifySchools(){
 
        $user           = $this->session->userdata('user');
        if(empty($user)){redirect('Menu/main');}
        $data['user']   = $user;
        $uid            = $user['user_id'];
        $uyid           =  $user['type_id'];
        $this->load->model('Menu_model');
        $dt             = $this->Menu_model->get_utype($uyid);
        $dep_name       = $dt[0]->name;

        $preSchools         = $this->Menu_model->GetALLIdentificationsSchool();
        $firstDatas         = $preSchools['data1'];
        $sales_cid_array    = array_unique(array_column($firstDatas, 'sales_cid'));
        $sales_cids         = implode(',', $sales_cid_array);

        // Sales CID Wise BD Filter
        if(!empty($sales_cid_array)){

            $ourCompanys    = $this->Menu_model->CheckSalesCompnayNameBYCid($sales_cids,$uyid,$uid);

            // cid की list निकालें
            $cids           = array_column($ourCompanys, 'cid');
            // Filter करें
            $filtered       = array_filter($firstDatas, function($row) use ($cids) {
                return in_array($row->sales_cid, $cids);
            });

            // Index reset (optional)
            $filtered               = array_values($filtered);
            $preSchools['data1']    = $filtered;

        }

        $this->load->view('Functions/PreIdentifySchools',
        [
            'uid'           => $uid,
            'user'          => $user,
            'preSchools'    => $preSchools,
            'dep_name'      => $dep_name
        ]
        );
        
    }


