  public function transferSchoolsToCompany(){
 
        $user           = $this->session->userdata('user');
        if(empty($user)){redirect('Menu/main');}
        $data['user']   = $user;
        $uid            = $user['user_id'];
        $uyid           =  $user['type_id'];
        $this->load->model('Menu_model');
        $dt             = $this->Menu_model->get_utype($uyid);
        $dep_name       = $dt[0]->name;
        $this->load->library('session');

        $current_company_id = $this->input->post('current_company_id');
        $target_company_id  = $this->input->post('target_company_id');
        $selected_schools   = $this->input->post('selected_schools');   // Array
        $selected_schools_count =  count($selected_schools);
        $companyDetails     = $this->Menu_model->GetSalesCompnayNameBYCid($target_company_id);

        $compname           = $companyDetails[0]->compname;

        if(!in_array($uyid,[1,2])){
            $this->session->set_flashdata('error_message', '* You are not Authrized Person. Please Contact Your Admin or Super Admin.');
            redirect('Menu/PreIdentifySchoolsLists/'.$current_company_id);
        }

        if(count($companyDetails) == 0){
            $this->session->set_flashdata('error_message', '* Company Details Not Found. Invalid CID');
            redirect('Menu/PreIdentifySchoolsLists/'.$current_company_id);
        }
        if($selected_schools_count == 0){
            $this->session->set_flashdata('error_message', '* Please Select at least one School.');
            redirect('Menu/PreIdentifySchoolsLists/'.$current_company_id);
        }

        $db3    = $this->load->database('db3', TRUE);

        foreach($selected_schools as $rsid){

        $schoolTransferDatas = [
            'clientname' => "$compname",
            'sales_cid' => "$target_company_id"
        ];

        $db3->where('id', $rsid);
        $update = $db3->update('spd_request', $schoolTransferDatas);

        if ($update) {
                $logdata = [
                    'rsid'       => $rsid,
                    'cid'        => $current_company_id,
                    'to_cid'     => $target_company_id,
                    'by_uid'     => $uid,
                    'remarks'    => "Sucesss",
                    'created_at' => date('Y-m-d H:i:s'),
                    'updated_at' => date('Y-m-d H:i:s')
                ];
                $insert = $this->db->insert('spd_request_transfer_log', $logdata);
                echo "Updated Successfully";
        } 

        }

        $this->session->set_flashdata('error_message', '* School Transfer Successfull.');
        redirect('Menu/PreIdentifySchools/');

    }

